window.__PDS_SEARCH__=[{"fqn":"health.html","name":"Architecture Health","kind":"page","summary":"Errors, warnings, and principle lints","text":"","module":"","href":"health.html"},{"fqn":"cli","name":"cli","kind":"module","summary":"","text":"","module":"cli","href":"module/cli.html"},{"fqn":"cli::AddOpts","name":"AddOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-AddOpts"},{"fqn":"cli::Args","name":"Args","kind":"component","summary":"Parses argv with clap-derive into the chosen subcommand and its options, then\ndispatches to the matching command handler.","text":"","module":"cli","href":"module/cli.html#cli-Args"},{"fqn":"cli::CheckCmd","name":"CheckCmd","kind":"component","summary":"`pds check` — parse and statically check one file, print each diagnostic as\n`path:line:col: severity: message`, and exit non-zero on any error-severity\ndiagnostic. Emits no diagram.","text":"","module":"cli","href":"module/cli.html#cli-CheckCmd"},{"fqn":"cli::CheckOpts","name":"CheckOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-CheckOpts"},{"fqn":"cli::Cli","name":"Cli","kind":"container","summary":"`crates/pseudoscript` — the binary crate (`pds`). The composition root and\nonly I/O edge; a thin frontend that wires the pure library crates to disk,\nHTTP, and a filesystem watcher.","text":"","module":"cli","href":"module/cli.html#cli-Cli"},{"fqn":"cli::Command","name":"Command","kind":"data","summary":"The subcommand clap parsed from argv, with its resolved options.","text":"","module":"cli","href":"module/cli.html#cli-Command"},{"fqn":"cli::Deps","name":"Deps","kind":"component","summary":"`pds add`/`install`/`update`/`remove`/`list` — git workspace dependency\nmanagement (§8.3). `add` resolves a git URL into `pds.toml` + `pds.lock` and\nvendors it; `install` restores `pds_modules/` from the lock; `update`\nre-pins; `remove` drops one; `list` discovers every workspace under a root.\nResolution delegates to `project`; fetching is the CLI's I/O.","text":"","module":"cli","href":"module/cli.html#cli-Deps"},{"fqn":"cli::DocCmd","name":"DocCmd","kind":"component","summary":"`pds doc` — the headline command (ADR-017). Load the workspace, check it per\nmodule (reported but non-fatal, like `cargo doc` — the same findings feed the\nsite's health page), project the resolved graph, and render a static doc\nsite. The output format is resolved by precedence — an explicit `--format`\nover the manifest `[doc].format`, else HTML — then a fork renders the SSR\nHTML site (every diagram as server SVG, logo copied) or a flat Markdown site\n(SVG assets, no logo). `--serve` hosts the HTML site over HTTP; `--watch`\nadds a filesystem watcher and browser live reload; both are skipped for\nMarkdown output, which only writes.","text":"","module":"cli","href":"module/cli.html#cli-DocCmd"},{"fqn":"cli::DocOpts","name":"DocOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-DocOpts"},{"fqn":"cli::EvalCmd","name":"EvalCmd","kind":"component","summary":"`pds eval` — read a model from stdin and statically check it, printing each\ndiagnostic as `<stdin>:line:col: severity: message` and exiting non-zero on\nany error. The fileless path: an agent pipes a snippet to check it without\nwriting a file.","text":"","module":"cli","href":"module/cli.html#cli-EvalCmd"},{"fqn":"cli::FmtCmd","name":"FmtCmd","kind":"component","summary":"`pds fmt` — format to canonical PseudoScript; `--write` overwrites the file in\nplace, otherwise prints to stdout. A parse error is reported and the file is\nleft untouched.","text":"","module":"cli","href":"module/cli.html#cli-FmtCmd"},{"fqn":"cli::FmtOpts","name":"FmtOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-FmtOpts"},{"fqn":"cli::HttpServer","name":"HttpServer","kind":"component","summary":"HTTP host for the generated site (`--serve`/`--watch`): `tiny_http` on\n`127.0.0.1:port`, maps `/` to `index.html`, rejects paths escaping the output\ndir, and on watch injects a live-reload poll and answers `/__livereload` with\nthe current version. Blocks until the process is stopped.","text":"","module":"cli","href":"module/cli.html#cli-HttpServer"},{"fqn":"cli::InitCmd","name":"InitCmd","kind":"component","summary":"`pds init` — bootstrap a workspace: write `pds.toml` and a starter `main.pds`.\nRefuses to overwrite an existing manifest; the starter is written only when\nabsent.","text":"","module":"cli","href":"module/cli.html#cli-InitCmd"},{"fqn":"cli::IoError","name":"IoError","kind":"data","summary":"A filesystem, parse-config, or serving failure surfaced to the CLI exit code.","text":"","module":"cli","href":"module/cli.html#cli-IoError"},{"fqn":"cli::ListOpts","name":"ListOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-ListOpts"},{"fqn":"cli::Loader","name":"Loader","kind":"component","summary":"The CLI loader: resolves the project root and reads its modules through the\n`project` crate (the shared filesystem edge), then parses the cli-specific\n`[doc]` table on top. Root-finding and module-walking are `project`'s job;\nthe manifest's doc config is the CLI's.","text":"","module":"cli","href":"module/cli.html#cli-Loader"},{"fqn":"cli::LspHost","name":"LspHost","kind":"component","summary":"`pds lsp` — boot a Tokio runtime and launch the language server over stdio.\nSpawned as a child process by an editor (`context::Editor.openDocument`).","text":"","module":"cli","href":"module/cli.html#cli-LspHost"},{"fqn":"cli::OutlineCmd","name":"OutlineCmd","kind":"component","summary":"`pds outline` — walk the workspace's modules, build its graph, and print the\nsymbol outline as JSON: each node's `fqn`, `name`, `kind`, `parent`, whether it\nis a triggered flow entry, and its declaration site. The structure tree an\neditor draws. Outlining reads the walked modules straight, skipping the manifest\n`[doc]` parse and dependency resolution: the structure tree never depends on\npresentation config or external modules.","text":"","module":"cli","href":"module/cli.html#cli-OutlineCmd"},{"fqn":"cli::OutlineOpts","name":"OutlineOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-OutlineOpts"},{"fqn":"cli::ReferenceCmd","name":"ReferenceCmd","kind":"component","summary":"`pds lang` (alias `spec`) and `pds skill` — print the bundled, version-pinned\nlanguage reference and the authoring skill to stdout. Fed to an LLM to author\n`.pds`; no workspace needed.","text":"","module":"cli","href":"module/cli.html#cli-ReferenceCmd"},{"fqn":"cli::RemoveOpts","name":"RemoveOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-RemoveOpts"},{"fqn":"cli::SvgCmd","name":"SvgCmd","kind":"component","summary":"`pds svg` — render a single diagram to a self-contained SVG on stdout. With\n`--symbol`, draws that symbol's fitting view; otherwise draws `--view` (paired\nwith `--target`) over the whole workspace. The static counterpart of the IDE\ncanvas. Like `pds outline`, it reads the walked modules straight, skipping the\nmanifest `[doc]` parse and dependency resolution: a diagram never depends on\npresentation config or external modules.","text":"","module":"cli","href":"module/cli.html#cli-SvgCmd"},{"fqn":"cli::SvgOpts","name":"SvgOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-SvgOpts"},{"fqn":"cli::TokensCmd","name":"TokensCmd","kind":"component","summary":"`pds tokens` — print the conformance token stream (`KIND@line:col \"lexeme\"`)\nto stdout, for debugging the lexer.","text":"","module":"cli","href":"module/cli.html#cli-TokensCmd"},{"fqn":"cli::TokensOpts","name":"TokensOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-TokensOpts"},{"fqn":"cli::UpgradeCmd","name":"UpgradeCmd","kind":"component","summary":"`pds upgrade` — download a release and install it over the running binary.","text":"","module":"cli","href":"module/cli.html#cli-UpgradeCmd"},{"fqn":"cli::UpgradeOpts","name":"UpgradeOpts","kind":"data","summary":"","text":"","module":"cli","href":"module/cli.html#cli-UpgradeOpts"},{"fqn":"cli::Watcher","name":"Watcher","kind":"component","summary":"Filesystem watcher (`--watch`, via `notify`): watches the project root\nrecursively, debounces each save burst, and on a relevant change rebuilds the\nsite and bumps the version the browser's live-reload poll reads. Events under\nthe output dir are ignored so writing the site never re-triggers a build.","text":"","module":"cli","href":"module/cli.html#cli-Watcher"},{"fqn":"cli::Workspace","name":"Workspace","kind":"data","summary":"The loaded project: the `[doc]` config, the resolved output directory\n(`<root>/<out>`, default `target/doc`), every module sorted by FQN, the\ndependency-name-prefixed dependency modules (§8.3; empty without a `pds.lock`),\nand the preferred doc output format. Produced from the nearest `pds.toml`.","text":"","module":"cli","href":"module/cli.html#cli-Workspace"},{"fqn":"context","name":"context","kind":"module","summary":"","text":"","module":"context","href":"module/context.html"},{"fqn":"context::Developer","name":"Developer","kind":"person","summary":"Author of architecture models: edits `.pds` files in an IDE and runs the CLI.","text":"","module":"context","href":"module/context.html#context-Developer"},{"fqn":"context::Editor","name":"Editor","kind":"system","summary":"IDEs that speak the Language Server Protocol (VS Code, Neovim, …). The editor\nspawns `pds lsp` as a child process and drives it over stdio: it streams\ndocument changes to the server and renders the diagnostics it publishes.","text":"","module":"context","href":"module/context.html#context-Editor"},{"fqn":"context::Pseudoscript","name":"Pseudoscript","kind":"system","summary":"The PseudoScript CLI — loads a `.pds` workspace into one resolved graph and\ndocuments it as a static site, or serves the language to editors. Cross-system\ncallers couple to these published faces; the containers stay behind them.","text":"","module":"context","href":"module/context.html#context-Pseudoscript"},{"fqn":"doc","name":"doc","kind":"module","summary":"","text":"","module":"doc","href":"module/doc.html"},{"fqn":"doc::Assets","name":"Assets","kind":"component","summary":"Ships the prebuilt presentation bundles, authored in the `web/` Svelte package and\nembedded at build time (LANG.md §9.3). `style.css`, `client.js`, and\n`universe.js` ship once at the site root; `ssr.js` is build-time only — the\nengine (`Doc::Ssr`) evaluates it and it is never written to the site. The\nuniverse bundle is the only one that carries WebGL; the SSR bundle never\ndoes.","text":"","module":"doc","href":"module/doc.html#doc-Assets"},{"fqn":"doc::Call","name":"Call","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-Call"},{"fqn":"doc::Codec","name":"Codec","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-Codec"},{"fqn":"doc::Crumb","name":"Crumb","kind":"data","summary":"One breadcrumb hop: its label and href; the trailing crumb (the current\npage) carries no href.","text":"","module":"doc","href":"module/doc.html#doc-Crumb"},{"fqn":"doc::DiagnosticInput","name":"DiagnosticInput","kind":"data","summary":"One host-prepared diagnostic, positioned in its module's source: severity\nword (`error`/`warning`), the stable rule code and its principle-article URL\n(empty for plain diagnostics), the message, and the 1-based line/column with\nthe byte span. The host computes line/column once — this crate never sees\nmodule sources.","text":"","module":"doc","href":"module/doc.html#doc-DiagnosticInput"},{"fqn":"doc::Diagram","name":"Diagram","kind":"data","summary":"A diagram figure. Every view — C4, sequence, data, feature — ships as\ndeterministic server-rendered SVG, identical to `pds svg` (the client adds\npan/zoom only); `kind` is the view word (`c4`/`sequence`/`entity`/`flow`)\nthe figure exposes as its `data-diagram` hook. `Empty` marks a view that\nfailed to project.","text":"","module":"doc","href":"module/doc.html#doc-Diagram"},{"fqn":"doc::Diagrams","name":"Diagrams","kind":"component","summary":"The bridge into `emit`: project a view into a `Scene` and render it to the\nsame deterministic SVG `pds svg` emits, under the adaptive palette so the\nfigure follows the site theme. A view that fails to project degrades to an\n`Empty` placeholder rather than aborting the build — the cargo-doc stance\nthat a partial model still documents. The client adds pan/zoom around the\nfigure; it never re-lays-out.","text":"","module":"doc","href":"module/doc.html#doc-Diagrams"},{"fqn":"doc::Doc","name":"Doc","kind":"container","summary":"`crates/pseudoscript-doc`. Turns a resolved graph into a Svelte-rendered,\ncargo-doc-style site that fully represents the system: each node's `///`\ndocs and relationships on its page, every diagram as deterministic\nserver-rendered SVG, the 3D universe with its flows, the architecture-health\nreport, and a static full-text search index. Pure: returns in-memory files,\nthe CLI writes.","text":"","module":"doc","href":"module/doc.html#doc-Doc"},{"fqn":"doc::DocBody","name":"DocBody","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-DocBody"},{"fqn":"doc::DocConfig","name":"DocConfig","kind":"data","summary":"Site presentation, filled by the CLI from the `[doc]` table of `pds.toml`.\n`[doc]` tunes presentation only, never what is documented.","text":"","module":"doc","href":"module/doc.html#doc-DocConfig"},{"fqn":"doc::DocGroup","name":"DocGroup","kind":"data","summary":"One `[[doc.sidebar]]` group of authored Markdown pages: a heading and its\nordered pages, rendered above the auto-generated module tree.","text":"","module":"doc","href":"module/doc.html#doc-DocGroup"},{"fqn":"doc::DocPage","name":"DocPage","kind":"data","summary":"One authored Markdown page: its sidebar title, the source path (relative to\n`pds.toml`) from which the host and this crate derive the same stable slug,\nand the raw Markdown the host has already loaded, rendered to HTML at build\ntime. The crate reads `markdown`; `path` only names the page, never loads it.","text":"","module":"doc","href":"module/doc.html#doc-DocPage"},{"fqn":"doc::Empty","name":"Empty","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-Empty"},{"fqn":"doc::Engine","name":"Engine","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-Engine"},{"fqn":"doc::Escape","name":"Escape","kind":"component","summary":"All user text — node names, `///` docs, tags, the site title — is carried raw in\nthe props and escaped on interpolation by the renderer; this escaper guards the\nRust-owned document shell, where the title and theme become HTML attributes.","text":"","module":"doc","href":"module/doc.html#doc-Escape"},{"fqn":"doc::Health","name":"Health","kind":"component","summary":"Positions the host's diagnostics in the documentation: prepares raw\nper-module findings (line/column from sources), attributes each to the node\nwhose section it belongs on, and builds the health page and the per-section\nbadges. Attribution is positional: the node whose declaration starts\nclosest before the diagnostic's span owns it, a callable lifting to its\nowner; a span no node encloses falls back to the module page.","text":"","module":"doc","href":"module/doc.html#doc-Health"},{"fqn":"doc::HealthEntry","name":"HealthEntry","kind":"data","summary":"One architecture-health finding, attributed to the node whose section it\nbelongs on: the diagnostic fields plus the owning node's FQN and the\n(prefixed) href to its section — the module page when no node encloses the\nspan.","text":"","module":"doc","href":"module/doc.html#doc-HealthEntry"},{"fqn":"doc::HealthPage","name":"HealthPage","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-HealthPage"},{"fqn":"doc::Highlight","name":"Highlight","kind":"component","summary":"Highlights fenced code blocks at build time, so the shipped site needs no\nclient highlighter and one deterministic output serves every theme:\nPseudoScript through the toolchain's own lexer, emitting class-based spans\ncoloured by the site stylesheet. Any other language passes through escaped\nand unhighlighted — an embedded grammar set for common languages is a\ndeliberate future extension (it would bloat the IDE wasm today).","text":"","module":"doc","href":"module/doc.html#doc-Highlight"},{"fqn":"doc::IndexPage","name":"IndexPage","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-IndexPage"},{"fqn":"doc::Markdown","name":"Markdown","kind":"component","summary":"Renders an authored `[[doc.sidebar]]` page's Markdown source into the HTML that\nfills its `Doc` page body (LANG.md §9.3). The host has already loaded the\nsource into the page's `markdown`; this crate does no I/O and renders that\ncontent in memory. The rendered HTML carries through unescaped as trusted\nauthored content.","text":"","module":"doc","href":"module/doc.html#doc-Markdown"},{"fqn":"doc::MarkdownSite","name":"MarkdownSite","kind":"component","summary":"The static Markdown output mode: turns the same per-page props the HTML\nrenderer consumes into flat `.md` files, each diagram a standalone `.svg`\nasset referenced as an image. The universe page renders as text lists\n(nodes by level, edges with traffic, each flow's legs); the health page as\na table with article links. No SSR engine, no shared assets, no logo — the\nengine-free site for wikis and code hosts.","text":"","module":"doc","href":"module/doc.html#doc-MarkdownSite"},{"fqn":"doc::ModuleCard","name":"ModuleCard","kind":"data","summary":"A module card on the index: its FQN, the (prefixed) href to its page, and an\n\"N item(s)\" line.","text":"","module":"doc","href":"module/doc.html#doc-ModuleCard"},{"fqn":"doc::ModulePage","name":"ModulePage","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-ModulePage"},{"fqn":"doc::NavLink","name":"NavLink","kind":"data","summary":"One header navigation link, its href prefixed for the page's depth; `badge`\ncarries the Health page's finding count (empty elsewhere).","text":"","module":"doc","href":"module/doc.html#doc-NavLink"},{"fqn":"doc::NodeHref","name":"NodeHref","kind":"data","summary":"A universe node's documentation link: its id and the (prefixed) href to its\nsection, so clicking a sphere can navigate to the docs.","text":"","module":"doc","href":"module/doc.html#doc-NodeHref"},{"fqn":"doc::NodeSection","name":"NodeSection","kind":"data","summary":"One node's documentation section: head fields, `///` docs, tags, relationship\ngroups, scenario cards, embedded diagrams, and the health findings attributed\nto the node (rendered as inline badges).","text":"","module":"doc","href":"module/doc.html#doc-NodeSection"},{"fqn":"doc::NodeUrl","name":"NodeUrl","kind":"data","summary":"A resolved cross-reference target: the module page it lives on and its in-page\nanchor id. A cross-link uses these to build an `href`; an unresolved FQN has no\nentry and renders as plain text.","text":"","module":"doc","href":"module/doc.html#doc-NodeUrl"},{"fqn":"doc::PageBody","name":"PageBody","kind":"data","summary":"The page body: the landing index, one authored doc page, one module's page,\nthe 3D universe, or the architecture-health report.","text":"","module":"doc","href":"module/doc.html#doc-PageBody"},{"fqn":"doc::PageProps","name":"PageProps","kind":"data","summary":"The serialisable model for one page, handed to the Svelte server renderer.\nEvery derived value (resolved hrefs, anchors, edge labels, counts) is\nprecomputed here so the Svelte components do no graph logic. User text is\ncarried raw — the renderer escapes it on interpolation. `docGroups` carries\nthe authored `[[doc.sidebar]]` navigation shown above the module tree;\n`nav` carries the header links (Overview, Universe, Health with its finding\ncount); `crumbs` is the breadcrumb trail. Only the universe page's props are\nalso embedded in the document, for its 3D island — every other page ships no\npage data.","text":"","module":"doc","href":"module/doc.html#doc-PageProps"},{"fqn":"doc::Pages","name":"Pages","kind":"component","summary":"Projects the resolved graph into per-page `PageProps` — pure data, no markup.\nBuilds the index props (title, context diagram, module cards), each module page's\nnode sections, and the depth-prefixed sidebar tree mirroring the C4 hierarchy.","text":"","module":"doc","href":"module/doc.html#doc-Pages"},{"fqn":"doc::RelGroup","name":"RelGroup","kind":"data","summary":"One relationship group (\"Parent\", \"Inbound\", or \"Outbound\") and its endpoints.","text":"","module":"doc","href":"module/doc.html#doc-RelGroup"},{"fqn":"doc::RelItem","name":"RelItem","kind":"data","summary":"One relationship endpoint: the edge-kind word, whether to draw the outbound\narrow, the endpoint FQN, its resolved href (absent → plain text), and any label.","text":"","module":"doc","href":"module/doc.html#doc-RelItem"},{"fqn":"doc::Relationships","name":"Relationships","kind":"component","summary":"Renders a node's relationships (LANG.md §9.3): its `for`/owner parent, inbound\nedges, and outbound edges, skipping the structural `for`-parent edge kind. Each\nendpoint is a cross-link when its FQN resolves, plain text otherwise.","text":"","module":"doc","href":"module/doc.html#doc-Relationships"},{"fqn":"doc::RenderError","name":"RenderError","kind":"data","summary":"Why server-rendering a page failed. Every variant is a defect in the bundle, the\nengine, or the props codec — never user model data; well-formed props always\nrender.","text":"","module":"doc","href":"module/doc.html#doc-RenderError"},{"fqn":"doc::RenderedPage","name":"RenderedPage","kind":"data","summary":"The server-render result for one page: the `<svelte:head>` contents and the\nrendered body markup, dropped into the document shell.","text":"","module":"doc","href":"module/doc.html#doc-RenderedPage"},{"fqn":"doc::ScenarioCard","name":"ScenarioCard","kind":"data","summary":"One BDD scenario card: name, `///` docs, tags, the ordered steps, and the\nfeature's flow figure (LANG.md §9.5).","text":"","module":"doc","href":"module/doc.html#doc-ScenarioCard"},{"fqn":"doc::Scenarios","name":"Scenarios","kind":"component","summary":"Renders the BDD scenario cards on a node's page: each `feature` targeting the node\nbecomes its given/when/then steps and its flow figure as a card (LANG.md §5.2,\n§9.3, §9.5). Empty when the node has no features.","text":"","module":"doc","href":"module/doc.html#doc-Scenarios"},{"fqn":"doc::SearchEntry","name":"SearchEntry","kind":"data","summary":"One record in the static full-text search index: the symbol or page's FQN,\ndisplay name, kind word, one-line summary, plain-text body, declaring\nmodule, and root-relative href. Sorted by href then FQN so the index is\ndeterministic.","text":"","module":"doc","href":"module/doc.html#doc-SearchEntry"},{"fqn":"doc::SearchIndex","name":"SearchIndex","kind":"component","summary":"Builds the static full-text search index the client palette queries: one\nrecord per linkable node, module page, and authored doc page, plus the\nuniverse and health pages. Shipped as a classic-script JS assignment\n(`search-index.js` setting a window global) so it loads under `file://` —\nnever fetched.","text":"","module":"doc","href":"module/doc.html#doc-SearchIndex"},{"fqn":"doc::SectionDiagnostic","name":"SectionDiagnostic","kind":"data","summary":"One inline badge on a node's section: the severity, rule code, article URL,\nmessage, and source line of a finding attributed to that node.","text":"","module":"doc","href":"module/doc.html#doc-SectionDiagnostic"},{"fqn":"doc::Shell","name":"Shell","kind":"component","summary":"Owns the document shell that wraps each server-rendered body — the part Rust\nrenders, not Svelte: doctype, `<html data-theme>`, font + stylesheet links,\nthe theme pre-paint script, and the classic deferred scripts. Scripts are\nclassic (never `type=\"module\"`) and shared data ships as JS-global files, so\nthe site works opened from disk (`file://`). Only the universe page embeds\nits props (`window.__DATA__`) — for its 3D island; every other page ships no\npage data and the client only progressively enhances.","text":"","module":"doc","href":"module/doc.html#doc-Shell"},{"fqn":"doc::SidebarDocGroup","name":"SidebarDocGroup","kind":"data","summary":"One `[[doc.sidebar]]` group in the authored-doc navigation: a heading and its\npage links, shown above the module tree.","text":"","module":"doc","href":"module/doc.html#doc-SidebarDocGroup"},{"fqn":"doc::SidebarDocItem","name":"SidebarDocItem","kind":"data","summary":"One authored doc-page link in the sidebar: its title and the page href, already\nprefixed for the page's depth.","text":"","module":"doc","href":"module/doc.html#doc-SidebarDocItem"},{"fqn":"doc::SidebarModule","name":"SidebarModule","kind":"data","summary":"One sidebar entry: a module-page link and its node tree, hrefs already prefixed\nfor the page's depth.","text":"","module":"doc","href":"module/doc.html#doc-SidebarModule"},{"fqn":"doc::SidebarNode","name":"SidebarNode","kind":"data","summary":"One node in the sidebar tree, recursing into its same-module children.","text":"","module":"doc","href":"module/doc.html#doc-SidebarNode"},{"fqn":"doc::Site","name":"Site","kind":"data","summary":"The whole generated site as in-memory files, in deterministic order: the index,\none page per authored doc (`[[doc.sidebar]]`, in declaration order), then one\npage per module sorted by FQN, plus the shared assets. The doc crate does no\nI/O; the CLI writes each file under the configured output directory.","text":"","module":"doc","href":"module/doc.html#doc-Site"},{"fqn":"doc::SiteBuilder","name":"SiteBuilder","kind":"component","summary":"Orchestrates the whole site: build the URL map, project each page's props, server\nrender it through the SSR engine, wrap it in the document shell, and ship the\nshared assets plus the search index. Pure: returns in-memory `Site` files,\nwrites none.","text":"","module":"doc","href":"module/doc.html#doc-SiteBuilder"},{"fqn":"doc::SiteFile","name":"SiteFile","kind":"data","summary":"One generated file: a site-root-relative `/`-separated path (`index.html`,\n`module/banking.core.html`, `style.css`, `client.js`) and its complete contents.","text":"","module":"doc","href":"module/doc.html#doc-SiteFile"},{"fqn":"doc::SiteInfo","name":"SiteInfo","kind":"data","summary":"Site-wide presentation, identical across pages: the title, the\n`light`/`dark`/`system` theme word, the optional logo filename, and the\n`../` prefix to the site root for this page's depth.","text":"","module":"doc","href":"module/doc.html#doc-SiteInfo"},{"fqn":"doc::SiteStats","name":"SiteStats","kind":"data","summary":"The index page's stats strip: how many systems, containers, components,\nflows, and health findings the model carries.","text":"","module":"doc","href":"module/doc.html#doc-SiteStats"},{"fqn":"doc::Ssr","name":"Ssr","kind":"component","summary":"The server-side render boundary: a JSON-string-in / JSON-string-out seam to the\nJavaScript renderer. The native build embeds a `QuickJS` engine that evaluates the\nprebuilt `ssr.js` bundle (`Doc::Assets`) in-process; a wasm host implements the\nsame seam against its own JS engine. A defect here is a build-asset fault, never\nuser model data.","text":"","module":"doc","href":"module/doc.html#doc-Ssr"},{"fqn":"doc::Step","name":"Step","kind":"data","summary":"One scenario step: its keyword (given/when/then/and/but) and prose.","text":"","module":"doc","href":"module/doc.html#doc-Step"},{"fqn":"doc::Svg","name":"Svg","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-Svg"},{"fqn":"doc::Theme","name":"Theme","kind":"data","summary":"Doc-site colour scheme, written as the `data-theme` attribute on the root\n`<html>` to select a CSS variable set. `System` (the default) follows the\nOS `prefers-color-scheme`, overridable by the in-page toggle; `Light` and\n`Dark` pin the scheme.","text":"","module":"doc","href":"module/doc.html#doc-Theme"},{"fqn":"doc::UniversePage","name":"UniversePage","kind":"data","summary":"","text":"","module":"doc","href":"module/doc.html#doc-UniversePage"},{"fqn":"doc::Urls","name":"Urls","kind":"component","summary":"Maps every node FQN to its page path and anchor, and resolves cross-references to\nmodule-page-relative `href`s. A module page is `module/<dotted-fqn>.html`\n(`::` → `.`); a node is the `#<slug>` anchor within it. Only an FQN naming a real\nnode produces a link (LANG.md §9.3).","text":"","module":"doc","href":"module/doc.html#doc-Urls"},{"fqn":"dot","name":"dot","kind":"module","summary":"","text":"","module":"dot","href":"module/dot.html"},{"fqn":"dot::Box2","name":"Box2","kind":"data","summary":"An axis-aligned box: top-left corner and extent.","text":"","module":"dot","href":"module/dot.html#dot-Box2"},{"fqn":"dot::Cluster","name":"Cluster","kind":"data","summary":"A cluster (a `subgraph cluster_*`): its id, optional parent cluster, member\nnode ids, the margin kept outside its members, and the header band reserved on\nthe title side.","text":"","module":"dot","href":"module/dot.html#dot-Cluster"},{"fqn":"dot::ClusterBox","name":"ClusterBox","kind":"data","summary":"A laid-out cluster: its id and bounding box.","text":"","module":"dot","href":"module/dot.html#dot-ClusterBox"},{"fqn":"dot::Clusters","name":"Clusters","kind":"component","summary":"Cluster framing: compute each cluster's bounding box bottom-up so a nested\ncluster's box encloses its children (grown by their margins) and its direct\nmembers, with header room on the title side — `dot`'s recursive `rec_bb`.","text":"","module":"dot","href":"module/dot.html#dot-Clusters"},{"fqn":"dot::Dot","name":"Dot","kind":"container","summary":"`crates/pseudoscript-dot`. Runs the four-pass layered pipeline over a `Graph`\nto produce a `Layout`; also offers the experimental grid placer. The layout\nauthority `emit` drives for C4 diagrams.","text":"","module":"dot","href":"module/dot.html#dot-Dot"},{"fqn":"dot::Edge","name":"Edge","kind":"data","summary":"An input edge from `tail` to `head`, with its minimum rank span, its layout\nweight (higher pulls the endpoints into vertical alignment harder), and an\noptional label size that widens the rank gap to fit.","text":"","module":"dot","href":"module/dot.html#dot-Edge"},{"fqn":"dot::EdgeRoute","name":"EdgeRoute","kind":"data","summary":"A routed edge: the Bézier `spline` and its `polyline` approximation between\n`tail` and `head`, plus where its label sits.","text":"","module":"dot","href":"module/dot.html#dot-EdgeRoute"},{"fqn":"dot::Engine","name":"Engine","kind":"component","summary":"The layered engine: runs the faithful four-pass `dot` pipeline — rank, order,\nposition, splines — then frames the clusters and shifts the whole layout to\nthe origin. Deterministic and panic-free.","text":"","module":"dot","href":"module/dot.html#dot-Engine"},{"fqn":"dot::Graph","name":"Graph","kind":"data","summary":"The input graph the engine lays out: nodes, edges, clusters, the rank and node\nseparations, the rank direction, and any same-rank constraints.","text":"","module":"dot","href":"module/dot.html#dot-Graph"},{"fqn":"dot::Grid","name":"Grid","kind":"component","summary":"The experimental grid placer: an alternative to the layered pipeline that\nsnaps nodes to a grid, honouring drag-to-pin cells and searching for a\nplacement that minimises crossings, distance, and against-flow edges.","text":"","module":"dot","href":"module/dot.html#dot-Grid"},{"fqn":"dot::GridMeta","name":"GridMeta","kind":"data","summary":"Grid metadata carried back when the experimental grid placer ran: the grid\ndimensions, the cell pitch (centre-to-centre), the pixel centre of cell (0,0),\nand the width of the drag-room frame wrapping the grid — the geometry the IDE\nreads to map a drag onto a grid cell, recovering the raw cell from `origin`\nthen subtracting `pad`.","text":"","module":"dot","href":"module/dot.html#dot-GridMeta"},{"fqn":"dot::GridParams","name":"GridParams","kind":"data","summary":"Tunable weights for the experimental grid placer: how strongly it penalises\ncrossings, distance, and against-flow edges, the cell spacing, and how hard it\nsearches.","text":"","module":"dot","href":"module/dot.html#dot-GridParams"},{"fqn":"dot::Layout","name":"Layout","kind":"data","summary":"The layout result: the overall bounding box, the placed nodes, the routed\nedges, the cluster boxes, and — only when the grid placer ran — its grid\nmetadata.","text":"","module":"dot","href":"module/dot.html#dot-Layout"},{"fqn":"dot::LayoutState","name":"LayoutState","kind":"data","summary":"The structure that flows through a pipeline: the (possibly pass-mutated)\ninput graph and its current placement. A pass receives one, returns one, and\nthe framework hands it to the next pass; a re-ranking pass may edit `graph`\nand re-run the base layout.","text":"","module":"dot","href":"module/dot.html#dot-LayoutState"},{"fqn":"dot::Node","name":"Node","kind":"data","summary":"An input node: its id and its rendered size (the placer reserves this box).","text":"","module":"dot","href":"module/dot.html#dot-Node"},{"fqn":"dot::NodePos","name":"NodePos","kind":"data","summary":"A placed node: its id, centre point, and reserved size.","text":"","module":"dot","href":"module/dot.html#dot-NodePos"},{"fqn":"dot::Optimize","name":"Optimize","kind":"component","summary":"The `ShortenLongEdges` pass: a bounded, deterministic post-layout refinement.\nGreedily search for same-rank moves that reduce the sum of squared edge\nlengths (never merging across a cluster boundary), then re-lay-out with the\nimproving moves applied.","text":"","module":"dot","href":"module/dot.html#dot-Optimize"},{"fqn":"dot::Oracle","name":"Oracle","kind":"component","summary":"The test oracle: lays the same graph out with the real `dot` binary and\ncompares, so the port stays faithful rather than approximate. Skipped when\n`dot` is not installed.","text":"","module":"dot","href":"module/dot.html#dot-Oracle"},{"fqn":"dot::Order","name":"Order","kind":"component","summary":"Pass 2 — ordering: order nodes within each rank to minimise edge crossings,\ninserting virtual nodes for long edges so they route through thin lanes.","text":"","module":"dot","href":"module/dot.html#dot-Order"},{"fqn":"dot::Pass","name":"Pass","kind":"data","summary":"One stage of the composable post-layout pipeline: same structure in, same\nstructure out, so passes fold freely. `ShortenLongEdges` is the long-edge\noptimiser; `GridPlacement` wraps the grid placer so it drops into a pipeline.\nNew behaviour is added by writing a pass, not by threading flags through the\nengine.","text":"","module":"dot","href":"module/dot.html#dot-Pass"},{"fqn":"dot::Pin","name":"Pin","kind":"data","summary":"A pin fixing a node to a grid cell: the node's index into `graph.nodes` (the\ncaller resolves the FQN) at a row and column. The IDE's drag-to-pin.","text":"","module":"dot","href":"module/dot.html#dot-Pin"},{"fqn":"dot::Pipeline","name":"Pipeline","kind":"component","summary":"The composable post-layout pipeline: the base layout produces the starting\n`LayoutState`; each `Pass` folds it into the next. A pass adjusts geometry\ndirectly or edits the input graph (e.g. adds same-rank hints) and re-runs the\nbase layout.","text":"","module":"dot","href":"module/dot.html#dot-Pipeline"},{"fqn":"dot::Position","name":"Position","kind":"component","summary":"Pass 3 — positioning: assign x-coordinates by network simplex on an auxiliary\ngraph (aligning nodes and straightening long edges), and y-coordinates per\nrank stacked with `ranksep` plus any label and cluster-header room.","text":"","module":"dot","href":"module/dot.html#dot-Position"},{"fqn":"dot::Pt","name":"Pt","kind":"data","summary":"A point in layout coordinates.","text":"","module":"dot","href":"module/dot.html#dot-Pt"},{"fqn":"dot::Rank","name":"Rank","kind":"component","summary":"Pass 1 — rank assignment: give each node an integer rank by network simplex,\nbanding each cluster onto contiguous ranks and honouring same-rank constraints.","text":"","module":"dot","href":"module/dot.html#dot-Rank"},{"fqn":"dot::RankDir","name":"RankDir","kind":"data","summary":"The rank direction: top-to-bottom (the C4 default) or left-to-right.","text":"","module":"dot","href":"module/dot.html#dot-RankDir"},{"fqn":"dot::SearchMode","name":"SearchMode","kind":"data","summary":"How the experimental grid placer searches for a placement: pick automatically\nby size, always the bounded heuristic, or brute-force exhaustive (tiny graphs\nonly).","text":"","module":"dot","href":"module/dot.html#dot-SearchMode"},{"fqn":"dot::Size","name":"Size","kind":"data","summary":"A width/height extent.","text":"","module":"dot","href":"module/dot.html#dot-Size"},{"fqn":"dot::Splines","name":"Splines","kind":"component","summary":"Pass 4 — splines: route each edge as a piecewise Bézier through its\nvirtual-node corridor, clipped to the endpoint borders, with a label point at\nthe polyline midpoint.","text":"","module":"dot","href":"module/dot.html#dot-Splines"},{"fqn":"emit","name":"emit","kind":"module","summary":"","text":"","module":"emit","href":"module/emit.html"},{"fqn":"emit::BoundaryFrame","name":"BoundaryFrame","kind":"data","summary":"An enclosing frame of a boundary view: the boundary node's FQN (so the canvas\ncan drill into it), title, C4 kind (frame accent), and the cluster rectangle.","text":"","module":"emit","href":"module/emit.html#emit-BoundaryFrame"},{"fqn":"emit::C4EdgeKind","name":"C4EdgeKind","kind":"data","summary":"The relationship a routed edge expresses: a body `call`, a synthesised\n`trigger` from an initiator, or a `from` `provenance` link. Maps from\n`model::EdgeKind`, dropping the structural `for`-parent link.","text":"","module":"emit","href":"module/emit.html#emit-C4EdgeKind"},{"fqn":"emit::C4Layout","name":"C4Layout","kind":"data","summary":"A dot-placed C4 view for the interactive canvas and the static SVG: canvas\nsize, placed node cards, routed edges, the enclosing boundary frames\n(outermost first; empty for a context view), and — only under experimental\ngrid placement — the grid geometry for drag-to-pin.","text":"","module":"emit","href":"module/emit.html#emit-C4Layout"},{"fqn":"emit::C4Scene","name":"C4Scene","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-C4Scene"},{"fqn":"emit::C4Tweaks","name":"C4Tweaks","kind":"data","summary":"Per-diagram C4 layout tweaks (the UI's \"Layout\" toggles): run the long-edge\noptimiser, lay out left-to-right instead of top-to-bottom, scale the spacing,\nand — experimentally — place by brute-force grid search instead of the layered\nengine, with its own cost dials and search mode.","text":"","module":"emit","href":"module/emit.html#emit-C4Tweaks"},{"fqn":"emit::C4View","name":"C4View","kind":"data","summary":"Which C4 view a `C4Scene` is — drives the golden header keyword.","text":"","module":"emit","href":"module/emit.html#emit-C4View"},{"fqn":"emit::Component","name":"Component","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-Component"},{"fqn":"emit::Container","name":"Container","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-Container"},{"fqn":"emit::Data","name":"Data","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-Data"},{"fqn":"emit::DataEntity","name":"DataEntity","kind":"data","summary":"One entity in a `data` ER view: its FQN, label, disclosed form, rows, whether\nit is the focal type, and its laid-out card rectangle.","text":"","module":"emit","href":"module/emit.html#emit-DataEntity"},{"fqn":"emit::DataLink","name":"DataLink","kind":"data","summary":"A field-type reference link between two entities in a data view: the\nreferencing and referenced FQNs and the field driving the reference.","text":"","module":"emit","href":"module/emit.html#emit-DataLink"},{"fqn":"emit::DataScene","name":"DataScene","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-DataScene"},{"fqn":"emit::Edges","name":"Edges","kind":"component","summary":"Builds the routed-edge set for a C4 scene from the graph's edges: maps each\n`model::EdgeKind` to a `C4EdgeKind` (dropping `for`-parent links), lifts each\nendpoint to the in-view node it belongs to, drops self-loops and\nout-of-view edges, then sorts and de-duplicates.","text":"","module":"emit","href":"module/emit.html#emit-Edges"},{"fqn":"emit::Emit","name":"Emit","kind":"container","summary":"`crates/pseudoscript-emit`. Projects a view into a `Scene` and renders it to\nSVG; C4 views are placed by the `dot` layered engine, the sequence/data/feature\nviews by the matching `layout` engine.","text":"","module":"emit","href":"module/emit.html#emit-Emit"},{"fqn":"emit::EmitError","name":"EmitError","kind":"data","summary":"Why projecting a view failed: the target FQN names no node, or names a node of\nthe wrong kind for the requested view.","text":"","module":"emit","href":"module/emit.html#emit-EmitError"},{"fqn":"emit::EntityForm","name":"EntityForm","kind":"data","summary":"The disclosed form of a data entity, driving the card's eyebrow and rows: a\nrecord of typed fields, a discriminated union of variants, or a black box.","text":"","module":"emit","href":"module/emit.html#emit-EntityForm"},{"fqn":"emit::EntityRow","name":"EntityRow","kind":"data","summary":"One row of a data entity: the field or variant name, its rendered type (empty\nfor a union variant), and the FQN of the data type this row targets when it\nreferences one.","text":"","module":"emit","href":"module/emit.html#emit-EntityRow"},{"fqn":"emit::Feature","name":"Feature","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-Feature"},{"fqn":"emit::FeatureScene","name":"FeatureScene","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-FeatureScene"},{"fqn":"emit::FeatureStepNode","name":"FeatureStepNode","kind":"data","summary":"One step box in a `feature` flow view: the step keyword, its prose, and the\nlaid-out box rectangle.","text":"","module":"emit","href":"module/emit.html#emit-FeatureStepNode"},{"fqn":"emit::Frame","name":"Frame","kind":"data","summary":"A nestable frame over a body of sequence items, drawn as an enclosing box\nwith its condition label.","text":"","module":"emit","href":"module/emit.html#emit-Frame"},{"fqn":"emit::FrameItem","name":"FrameItem","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-FrameItem"},{"fqn":"emit::FrameKind","name":"FrameKind","kind":"data","summary":"The kind of a sequence frame: `if`/`else` becomes an `alt` frame, `for`/\n`while` becomes a `loop` frame.","text":"","module":"emit","href":"module/emit.html#emit-FrameKind"},{"fqn":"emit::GridInfo","name":"GridInfo","kind":"data","summary":"The grid the experimental placement used, in absolute canvas coordinates:\ncell `(r, c)` is centred at `origin + (c·cellW, r·cellH)`; `pad` is the\ndrag-room frame, so a pixel maps to its pin cell by recovering the raw cell\nthen subtracting `pad`.","text":"","module":"emit","href":"module/emit.html#emit-GridInfo"},{"fqn":"emit::GridPin","name":"GridPin","kind":"data","summary":"A node the user has pinned to a grid cell (drag-to-pin), identified by FQN;\nthe emit layer resolves it to a `dot` node index for the current view. Honoured\nonly under experimental grid placement.","text":"","module":"emit","href":"module/emit.html#emit-GridPin"},{"fqn":"emit::GridSearch","name":"GridSearch","kind":"data","summary":"Which grid search the experimental grid placer runs — the UI's\nheuristic-vs-brute-force toggle. Mirrors `dot::SearchMode` so the IDE need not\ndepend on `dot`.","text":"","module":"emit","href":"module/emit.html#emit-GridSearch"},{"fqn":"emit::LaidOutEdge","name":"LaidOutEdge","kind":"data","summary":"A routed edge for the canvas/SVG: its endpoints (`source` stands for the wire\n`from`), kind, stacked labels, the engine's polyline (at least two points),\nthe label position at the polyline midpoint when labels exist, and whether it\ndraws dashed (a `from`-provenance edge).","text":"","module":"emit","href":"module/emit.html#emit-LaidOutEdge"},{"fqn":"emit::LaidOutNode","name":"LaidOutNode","kind":"data","summary":"A node card placed by the `dot` engine for the canvas/SVG: its FQN, C4 kind\n(accent and eyebrow), display label, optional `///` summary, and rectangle.","text":"","module":"emit","href":"module/emit.html#emit-LaidOutNode"},{"fqn":"emit::Layout","name":"Layout","kind":"component","summary":"Assigns geometry. Projection stamps each C4 scene with simple row-flow\ncoordinates (`solveC4`) — the panic-proof fallback geometry every scene\ncarries. The real placement runs at render/canvas time: `layoutC4` drives the\n`dot` layered engine (rank/order/position/splines), framing boundary children\nas a cluster, tuned by per-diagram `C4Tweaks` and drag-to-pin cells. The\nsequence/data/feature scenes are placed by the matching `layout` engine.","text":"","module":"emit","href":"module/emit.html#emit-Layout"},{"fqn":"emit::Lifeline","name":"Lifeline","kind":"data","summary":"A sequence lifeline (a participant): its FQN, C4 kind for the head card, the\nnode's `///` summary shown dimmed under the name, and the structural ancestry\npath under a container/component name. No coordinate — the sequence layout\nassigns the lifeline x.","text":"","module":"emit","href":"module/emit.html#emit-Lifeline"},{"fqn":"emit::Message","name":"Message","kind":"data","summary":"A message between two lifelines (or a self-message). `label` is the method\nname, or `Ok`/`Err`/empty for a return; `detail` is the type detail shown after\nit — a call's `(params): ret` signature or a return's concrete type.","text":"","module":"emit","href":"module/emit.html#emit-Message"},{"fqn":"emit::MessageItem","name":"MessageItem","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-MessageItem"},{"fqn":"emit::MessageKind","name":"MessageKind","kind":"data","summary":"The kind of a sequence message: a `call` to another lifeline, a `return` to\nthe caller, or a `self`-message on the owner's own lifeline.","text":"","module":"emit","href":"module/emit.html#emit-MessageKind"},{"fqn":"emit::PlacedNode","name":"PlacedNode","kind":"data","summary":"A node placed in a C4 view: its FQN, C4 kind, display label, optional `///`\nsummary (the card's dimmed description), the boundary it sits inside, and the\nlayout rectangle assigned by the placer.","text":"","module":"emit","href":"module/emit.html#emit-PlacedNode"},{"fqn":"emit::PointI","name":"PointI","kind":"data","summary":"An integer point on the canvas (a rounded layout coordinate).","text":"","module":"emit","href":"module/emit.html#emit-PointI"},{"fqn":"emit::Projector","name":"Projector","kind":"component","summary":"Projects a `View` out of the graph (LANG.md §9): dispatches on the view\nvariant, collecting nodes and edges for a C4 scene or tracing a callable body\nfor a sequence scene, then hands off to the placer. Fails with `EmitError`\nwhen the view's target is missing or the wrong kind.","text":"","module":"emit","href":"module/emit.html#emit-Projector"},{"fqn":"emit::Rect","name":"Rect","kind":"data","summary":"An axis-aligned layout rectangle in renderer coordinates.","text":"","module":"emit","href":"module/emit.html#emit-Rect"},{"fqn":"emit::RoutedEdge","name":"RoutedEdge","kind":"data","summary":"An edge routed between two C4 nodes: its endpoints, kind, and the merged call\nlabels (sorted and de-duplicated; empty for a trigger or provenance edge).\nParallel calls between the same pair collapse into one multi-label edge.\n`source` is the wire field `from`, renamed because `from` is a PseudoScript\nkeyword.","text":"","module":"emit","href":"module/emit.html#emit-RoutedEdge"},{"fqn":"emit::Scene","name":"Scene","kind":"data","summary":"A laid-out diagram: the notation-neutral IR the SVG renderer consumes. A C4\nscene carries placed nodes and routed edges; a sequence scene carries\nlifelines and ordered messages with nested frames. This IR is the generation\nconformance surface (ADR-017): coordinates are carried for the renderer only,\nnever serialised to the golden.","text":"","module":"emit","href":"module/emit.html#emit-Scene"},{"fqn":"emit::SeqItem","name":"SeqItem","kind":"data","summary":"One ordered item in a sequence trace: a message or a nested frame.","text":"","module":"emit","href":"module/emit.html#emit-SeqItem"},{"fqn":"emit::Sequence","name":"Sequence","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-Sequence"},{"fqn":"emit::SequenceScene","name":"SequenceScene","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-SequenceScene"},{"fqn":"emit::SvgRenderer","name":"SvgRenderer","kind":"component","summary":"Renders a laid-out `Scene` to standalone SVG markup — string-building, no\ntemplate engine and no headless browser (LANG.md §9.3, ADR-017). Dispatches\non the scene variant; the layout engine is wrapped so no input panics the\nrender, falling back to the scene's own simple coordinates.","text":"","module":"emit","href":"module/emit.html#emit-SvgRenderer"},{"fqn":"emit::Trace","name":"Trace","kind":"component","summary":"Walks a callable's body trace into ordered sequence items, registering each\nparticipant on first appearance (LANG.md §9.2, §7). A real trigger's\ninitiator leads as the first lifeline with a synthesised inbound call;\nabsent a trigger the owner leads. A `call` is a message to the target; a\ndisclosed callee expands inline; a same-node call is a self-message that\nexpands its disclosed body inline too; a return\nmarks `Ok`/`Err`; `if`/`else` nests an `alt` frame, `for`/`while` a `loop`\nframe.","text":"","module":"emit","href":"module/emit.html#emit-Trace"},{"fqn":"emit::UnknownNode","name":"UnknownNode","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-UnknownNode"},{"fqn":"emit::View","name":"View","kind":"data","summary":"Which view to project from the graph (LANG.md §9). Context is the C1 whole;\nContainer/Component zoom into one boundary; Sequence traces one entry point;\nData draws a `data` type's entity (ER) view (§9.4); Feature draws a `feature`\nscenario's flow (§9.5).","text":"","module":"emit","href":"module/emit.html#emit-View"},{"fqn":"emit::WrongKind","name":"WrongKind","kind":"data","summary":"","text":"","module":"emit","href":"module/emit.html#emit-WrongKind"},{"fqn":"format","name":"format","kind":"module","summary":"","text":"","module":"format","href":"module/format.html"},{"fqn":"format::Format","name":"Format","kind":"container","summary":"`crates/pseudoscript-format`. The canonical formatter: parse, then\npretty-print the tree to one canonical form. The string-to-string entry the\nCLI and LSP depend on.","text":"","module":"format","href":"module/format.html#format-Format"},{"fqn":"format::FormatError","name":"FormatError","kind":"data","summary":"Why formatting failed. The only failure is unparseable input: `Parse`\ncarries the rendered error messages (one per diagnostic) for context, and\nthe caller keeps its original text.","text":"","module":"format","href":"module/format.html#format-FormatError"},{"fqn":"format::Formatter","name":"Formatter","kind":"component","summary":"Drives the headline flow: parse the source, short-circuit to\n`FormatError::Parse` if any error diagnostic surfaced, else hand the tree to\nthe printer for canonical text.","text":"","module":"format","href":"module/format.html#format-Formatter"},{"fqn":"format::Parse","name":"Parse","kind":"data","summary":"","text":"","module":"format","href":"module/format.html#format-Parse"},{"fqn":"format::Printer","name":"Printer","kind":"component","summary":"The canonical pretty-printer: walks the AST top-down, appending to a buffer,\nand emits one canonical form. Indentation is a level counter (two spaces\neach); leading trivia is normalised — blank-line runs collapse to at most one\nseparator and `//` / `/* */` comments reproduce at the current indent in\nsource order. Internals are black-boxed per construct; the top-level `print`\nflow is disclosed.","text":"","module":"format","href":"module/format.html#format-Printer"},{"fqn":"format::PrinterState","name":"PrinterState","kind":"data","summary":"The running pretty-printer state: the text buffer being built, the current\nnesting depth (two spaces each), and whether the current line has had its\nindentation written yet so further writes append in place.","text":"","module":"format","href":"module/format.html#format-PrinterState"},{"fqn":"ide","name":"ide","kind":"module","summary":"","text":"","module":"ide","href":"module/ide.html"},{"fqn":"ide::Bootstrap","name":"Bootstrap","kind":"component","summary":"Boots the IDE in a browser tab: load the one wasm bundle (IdeSession), then\nrestore the URL hash's workspace — a share link mounts in memory and needs\nno disk — or fall back to the launcher. File System Access support gates\nonly the disk features (open folder, save, watch): without it those actions\nare disabled with a notice, while share links and the bundled examples\nstill open.","text":"","module":"ide","href":"module/ide.html#ide-Bootstrap"},{"fqn":"ide::BrowserWorkspace","name":"BrowserWorkspace","kind":"data","summary":"The in-browser workspace state the session holds: the open `.pds` modules, the\n`pds.toml` manifest text, and the dependency modules resolved from\n`pds_modules/` as externals (LANG.md §8.3). Held in memory — a decoded\nsample/share link or a local directory loaded through the file-system port.\nEdits never leave the tab.","text":"","module":"ide","href":"module/ide.html#ide-BrowserWorkspace"},{"fqn":"ide::CodeMirrorAdapter","name":"CodeMirrorAdapter","kind":"component","summary":"The editor adapter over CodeMirror 6: the text/cursor model, the completion\nsource, the hover tooltip, the diagnostics gutter, and edit events forwarded\ninto the session. The only place CodeMirror specifics live — it drives the\nsession and applies the typed values it gets back.","text":"","module":"ide","href":"module/ide.html#ide-CodeMirrorAdapter"},{"fqn":"ide::Completion","name":"Completion","kind":"data","summary":"A completion candidate offered as the author types: the inserted label, the\ninteger LSP `CompletionItemKind` the editor maps to an icon, and detail text\n(absent for candidates with nothing to add).","text":"","module":"ide","href":"module/ide.html#ide-Completion"},{"fqn":"ide::DiagramCanvas","name":"DiagramCanvas","kind":"component","summary":"The diagram canvas: draws the **JSON** `Scene` interactively (Svelte Flow\npan/zoom over geometry positioned by `emit`'s layout engine for C4, a\ndepth-collapsible timeline for sequences), and exports the current view as\n**PNG or SVG**, both produced in the browser from the drawn diagram. JSON is\nthe draw format; no diagram image crosses the wasm surface. The editor\nport's diagram seam binds to this.","text":"","module":"ide","href":"module/ide.html#ide-DiagramCanvas"},{"fqn":"ide::Diagrams","name":"Diagrams","kind":"component","summary":"Diagram projection: builds the workspace graph and projects a view to the\nJSON `Scene` via `emit::Projector`; the host's canvas draws it. The wasm\nsurface carries only the JSON scene and layout — SVG and PNG are export\nconcerns of the canvas (PNG rasterised in the browser), and the static SVG\nform is a CLI/doc concern of the `emit` crate, not exposed here.","text":"","module":"ide","href":"module/ide.html#ide-Diagrams"},{"fqn":"ide::DocConfig","name":"DocConfig","kind":"data","summary":"The doc-site build input: the manifest plus each authored page's Markdown,\nloaded by the host. Field detail is the wasm boundary's concern.","text":"","module":"ide","href":"module/ide.html#ide-DocConfig"},{"fqn":"ide::Docs","name":"Docs","kind":"component","summary":"The doc-site builder: renders the whole site in-browser through the same\n`pseudoscript-doc` crate `pds doc` runs, driving SSR through a render\ncallback the host supplies (the browser's JS engine is the SSR engine) — so\nthe IDE writes the exact site the CLI ships, health page included. The site\nbuilds to the opened folder's `target/doc/` only; an in-memory workspace is\ntold to open a folder first (no blob-preview path).","text":"","module":"ide","href":"module/ide.html#ide-Docs"},{"fqn":"ide::FimClient","name":"FimClient","kind":"component","summary":"Provider-agnostic completion client: one `complete` contract over\nOpenAI-compatible HTTP, so one client covers Codestral, OpenRouter, Together,\nOllama, and vLLM. Stateless — the caller hands it the settings snapshot and\nowns cancellation (`GhostText` aborts the in-flight request on the next\nkeystroke; the client honours the abort). Every failure comes back as a\nclassified `ProviderError`, so the caller can surface why a request bailed.","text":"","module":"ide","href":"module/ide.html#ide-FimClient"},{"fqn":"ide::FimPrompt","name":"FimPrompt","kind":"data","summary":"The assembled fill-in-the-middle request: the windowed buffer text before and\nafter the caret, and the cached grammar primer that steers a general model to\nemit valid PseudoScript.","text":"","module":"ide","href":"module/ide.html#ide-FimPrompt"},{"fqn":"ide::FsAccessAdapter","name":"FsAccessAdapter","kind":"component","summary":"The file-system adapter over the browser File System Access API: directory\npicker, recursive walk for `.pds` modules, deriving each module's flat FQN\nfrom its path (LANG.md §8.1, ADR-031), `pds.lock` + `pds_modules/` reads for\ndependency externals, and per-file read/write through handles. The only place\nFS-Access specifics live; it pushes what it reads into the session via\n`mount`.","text":"","module":"ide","href":"module/ide.html#ide-FsAccessAdapter"},{"fqn":"ide::GhostText","name":"GhostText","kind":"component","summary":"Inline ghost-text completion over CodeMirror 6, beside the grammar dropdown:\nstructural candidates stay local and deterministic in `CodeMirrorAdapter`;\nthe remote model supplies only multi-token greyed text. CodeMirror has no\nnative inline-suggestion UI, so this is a custom view plugin rendering a\nwidget decoration at the caret — Tab accepts, Esc dismisses, any edit clears.","text":"","module":"ide","href":"module/ide.html#ide-GhostText"},{"fqn":"ide::GridPin","name":"GridPin","kind":"data","summary":"A node the user has dragged onto a grid cell, identified by FQN. Carried inside\n`LayoutTweaks`; honoured only under experimental grid placement.","text":"","module":"ide","href":"module/ide.html#ide-GridPin"},{"fqn":"ide::IdeSession","name":"IdeSession","kind":"container","summary":"`crates/pseudoscript-ide` — the IDE application, Rust compiled to a single\nwasm. It owns the workspace state and is the whole browser API: the host\npushes modules in (`mount`/`setSource`) and pulls every answer out as a\ntyped value — the session never calls the DOM, CodeMirror, or the File\nSystem Access API. It delegates language intelligence to `lsp_core` and\n`model::Checks`, diagrams to `emit::Projector`, the 3D universe to\n`universe::Adapter`, and the doc site to `doc::SiteBuilder` — each a Rust\nlibrary linked in, never a separate wasm. The one outbound seam is the doc\nbuild's SSR render callback the host supplies. Everything here is Rust.","text":"","module":"ide","href":"module/ide.html#ide-IdeSession"},{"fqn":"ide::LanguageSession","name":"LanguageSession","kind":"component","summary":"The language session: diagnostics, completion, hover, go-to, references,\nrename, outline, folding, and semantic tokens over the held workspace, every\nanswer delegated to the pure toolchain logic (`model::Checks` for diagnostics,\n`lsp_core` for cursor features) with the dependency externals bound. Every\nanswer is a typed value the host applies — the session pushes nothing at the\neditor.","text":"","module":"ide","href":"module/ide.html#ide-LanguageSession"},{"fqn":"ide::Launcher","name":"Launcher","kind":"component","summary":"The project launcher — the first surface. Offers the recents, open-a-folder,\nNew Project, and the bundled examples. Examples and share links mount in\nmemory and need no disk; only the disk actions gate on File System Access\nsupport. Dismissible, so the menus, help, and settings stay reachable\nwithout a project.","text":"","module":"ide","href":"module/ide.html#ide-Launcher"},{"fqn":"ide::LayoutTweaks","name":"LayoutTweaks","kind":"data","summary":"The IDE's per-diagram C4 layout toggles, crossing to JS as a typed object: run\nthe long-edge optimiser, the reading `orientation` (`\"tb\"`/`\"lr\"`), a `spacing`\npreset (`\"compact\"`/`\"comfortable\"`/`\"roomy\"`), and the experimental grid dials\nand pins. Translated to `emit::C4Tweaks` inside the session.","text":"","module":"ide","href":"module/ide.html#ide-LayoutTweaks"},{"fqn":"ide::LlmProvider","name":"LlmProvider","kind":"system","summary":"The author's configured OpenAI-compatible completion provider — hosted\n(OpenAI, Codestral, OpenRouter, Together) or local (Ollama, vLLM). External:\nthe IDE only speaks its HTTP API; transport and HTTP failures surface as\nclassified `ProviderError`s.","text":"","module":"ide","href":"module/ide.html#ide-LlmProvider"},{"fqn":"ide::LlmSettings","name":"LlmSettings","kind":"data","summary":"The author's AI-completion provider settings, persisted in the browser: the\nfeature toggle, the chosen preset (`\"ollama\"`, `\"openai\"`, or `\"custom\"` —\nthe presets pin the endpoint and wire shape so setup is pick-and-go), the\nOpenAI-compatible endpoint, the bring-your-own API key (stored in\nlocalStorage, sent only to the configured endpoint), the model id, and the\nwire shape (`\"fim\"` for a native fill-in-the-middle route, `\"chat\"` for the\nchat-completions fallback).","text":"","module":"ide","href":"module/ide.html#ide-LlmSettings"},{"fqn":"ide::LlmSettingsStore","name":"LlmSettingsStore","kind":"component","summary":"The author's AI-completion settings, persisted to browser localStorage and\nedited through the Settings dialog's \"AI Completion\" tab. Bring-your-own key:\nit never leaves the tab except on requests to the configured endpoint.\nSetup is preset-first: picking a provider applies its pinned endpoint and\nwire shape, so only the Custom preset exposes the raw fields. The store also\ncarries the session's last completion failure (never persisted) so the\nstatus chip and the settings tab can show why ghost text is bailing.","text":"","module":"ide","href":"module/ide.html#ide-LlmSettingsStore"},{"fqn":"ide::LocalInput","name":"LocalInput","kind":"data","summary":"One local-source dependency file the host reads for `dependencyModules`: the\ndependency name (ADR-026), its FQN within the dependency workspace, and its\nsource.","text":"","module":"ide","href":"module/ide.html#ide-LocalInput"},{"fqn":"ide::Occurrence","name":"Occurrence","kind":"data","summary":"One occurrence of a symbol: the module it lies in, its line/column span, the\nsource line text with the match offsets within it, and whether it is the\ndeclaration site.","text":"","module":"ide","href":"module/ide.html#ide-Occurrence"},{"fqn":"ide::OutlineNode","name":"OutlineNode","kind":"data","summary":"One row of the workspace outline: a node's FQN, simple name, C4 kind,\ncontainment parent (absent on roots), whether it is a triggered flow entry,\nits `///` summary (absent when undocumented), and its declaration line/column.","text":"","module":"ide","href":"module/ide.html#ide-OutlineNode"},{"fqn":"ide::PickError","name":"PickError","kind":"data","summary":"Why a folder pick yielded no workspace: the picker failed — the API missing,\nblocked by permission policy, or denied by the embedder. Distinct from a\nuser cancel, which is silent: a cancel is the user's choice, a failure is\nthe product's to explain.","text":"","module":"ide","href":"module/ide.html#ide-PickError"},{"fqn":"ide::ProviderError","name":"ProviderError","kind":"data","summary":"A classified completion-provider failure: `kind` is `\"network\"` (endpoint\nunreachable or CORS-blocked), `\"auth\"` (401/403), `\"notFound\"` (404 route or\nmodel), `\"timeout\"`, or `\"http\"` (any other non-OK status); `message` states\nwhat failed and `hint` names the fix for the configured provider (e.g. the\n`OLLAMA_ORIGINS` command for a CORS-blocked local Ollama).","text":"","module":"ide","href":"module/ide.html#ide-ProviderError"},{"fqn":"ide::References","name":"References","kind":"data","summary":"The find-references result for the symbol under the caret: the symbol's FQN, a\nhuman title, and every occurrence across the workspace.","text":"","module":"ide","href":"module/ide.html#ide-References"},{"fqn":"ide::RenameSelection","name":"RenameSelection","kind":"data","summary":"One occurrence the user chose to rename, keyed by the module FQN and the\n1-based line/column an `ide::Occurrence` reported. The rename rewrites only\nthe selected occurrences, not every match.","text":"","module":"ide","href":"module/ide.html#ide-RenameSelection"},{"fqn":"ide::RenamedSource","name":"RenamedSource","kind":"data","summary":"One module rewritten by a rename: its FQN and new source text.","text":"","module":"ide","href":"module/ide.html#ide-RenamedSource"},{"fqn":"ide::RenderedFile","name":"RenderedFile","kind":"data","summary":"One file of the rendered documentation site: its site-relative path and\ncontents.","text":"","module":"ide","href":"module/ide.html#ide-RenderedFile"},{"fqn":"ide::Samples","name":"Samples","kind":"component","summary":"The bundled example catalogue, discovered at build time from the samples\nfolder (one folder per example: meta.json, the `.pds` modules, `pds.toml`,\ndoc pages). Each entry doubles as a New-project template and as an\nin-memory workspace.","text":"","module":"ide","href":"module/ide.html#ide-Samples"},{"fqn":"ide::Universe","name":"Universe","kind":"component","summary":"The 3D universe: builds the software graph from the held workspace and flattens\nit to a snapshot the `ForceGraph` renders, with the entry-point flows traced\nin Rust. Delegates to the `universe` crate; the wasm surface carries only the\nflat snapshot and flows — positions are the renderer's.","text":"","module":"ide","href":"module/ide.html#ide-Universe"},{"fqn":"ide::UniverseEdge","name":"UniverseEdge","kind":"data","summary":"One directed relationship in the 3D graph, weighted by traffic (call count).\nThe wire field is `from`; `from` is a PseudoScript keyword, so the model\nnames it `source`.","text":"","module":"ide","href":"module/ide.html#ide-UniverseEdge"},{"fqn":"ide::UniverseNode","name":"UniverseNode","kind":"data","summary":"One node in the 3D relationship graph the IDE draws: its FQN, C4 level, and\ncontainment parent (absent on roots). The typed boundary form of a\n`universe::NodeOut`.","text":"","module":"ide","href":"module/ide.html#ide-UniverseNode"},{"fqn":"ide::UniverseSnapshot","name":"UniverseSnapshot","kind":"data","summary":"The 3D-view snapshot the session hands the `ForceGraph`: nodes and directed\nweighted edges, no positions (the renderer lays them out). The typed boundary\nform of a `universe::Snapshot`.","text":"","module":"ide","href":"module/ide.html#ide-UniverseSnapshot"},{"fqn":"ide::VendoredInput","name":"VendoredInput","kind":"data","summary":"One vendored git-dependency file the host reads for `dependencyModules`: its\n`pds_modules/` slug, its FQN within the dependency workspace (the host's\npath→FQN derivation, LANG.md §8.1), and its source.","text":"","module":"ide","href":"module/ide.html#ide-VendoredInput"},{"fqn":"ide::WebIde","name":"WebIde","kind":"container","summary":"`web-ide` — the IDE at `ide.pdscript.dev`: a SvelteKit shell on Cloudflare\nWorkers static assets. Pure glue — it loads the one wasm bundle and binds the\nadapters to the session's ports. It holds no language logic.","text":"","module":"ide","href":"module/ide.html#ide-WebIde"},{"fqn":"ide::Workspace","name":"Workspace","kind":"component","summary":"The in-memory project the session holds: the parsed modules keyed by FQN (an\nopen buffer overlays via `setSource`), the dependency externals, and the\nmemoised resolved workspace + graph — invalidated by any mutation, rebuilt\nonce for the query burst between keystrokes. Edits never leave the tab; an\nexplicit save writes through the host's file handles, not this session.","text":"","module":"ide","href":"module/ide.html#ide-Workspace"},{"fqn":"landing","name":"landing","kind":"module","summary":"","text":"","module":"landing","href":"module/landing.html"},{"fqn":"landing::Landing","name":"Landing","kind":"container","summary":"`web-landing` — the marketing site at `pdscript.dev`. A static Svelte build on\nCloudflare Workers static assets; no backend. It routes a visitor to one of\nthree surfaces and otherwise just tells the model-driven story.","text":"","module":"landing","href":"module/landing.html#landing-Landing"},{"fqn":"landing::Visitor","name":"Visitor","kind":"person","summary":"A prospective user reading the landing page.","text":"","module":"landing","href":"module/landing.html#landing-Visitor"},{"fqn":"layout","name":"layout","kind":"module","summary":"","text":"","module":"layout","href":"module/layout.html"},{"fqn":"layout::Activation","name":"Activation","kind":"data","summary":"An execution-activation bar on a lifeline, spanning a participant's first-to-\nlast involvement; `owner` marks the entry's focus lifeline.","text":"","module":"layout","href":"module/layout.html#layout-Activation"},{"fqn":"layout::Core","name":"Core","kind":"component","summary":"The shared geometry/text core: measures label and title widths, wraps\ndescriptions to a width, and accumulates bounding boxes. Every engine builds\non it, so text sizing and bounds math live in exactly one place.","text":"","module":"layout","href":"module/layout.html#layout-Core"},{"fqn":"layout::Diagram","name":"Diagram","kind":"data","summary":"A structural sequence diagram: the participants (lifelines) and the ordered\nitems — messages and nested fragments — traced down them. The sequence\nengine's input.","text":"","module":"layout","href":"module/layout.html#layout-Diagram"},{"fqn":"layout::Divider","name":"Divider","kind":"data","summary":"A horizontal split between two fragment sections: its y and the following\nsection's guard.","text":"","module":"layout","href":"module/layout.html#layout-Divider"},{"fqn":"layout::FragKind","name":"FragKind","kind":"data","summary":"The kind of a fragment frame: an `alt` (if/else) or a `loop` (for/while).","text":"","module":"layout","href":"module/layout.html#layout-FragKind"},{"fqn":"layout::Fragment","name":"Fragment","kind":"data","summary":"A nestable fragment over a body of items, drawn as an enclosing frame: its\nkind and the labelled sections it splits into (an `alt` has several).","text":"","module":"layout","href":"module/layout.html#layout-Fragment"},{"fqn":"layout::FragmentItem","name":"FragmentItem","kind":"data","summary":"","text":"","module":"layout","href":"module/layout.html#layout-FragmentItem"},{"fqn":"layout::Item","name":"Item","kind":"data","summary":"One ordered item down the lifelines: a message or a nested fragment.","text":"","module":"layout","href":"module/layout.html#layout-Item"},{"fqn":"layout::Layout","name":"Layout","kind":"container","summary":"`crates/pseudoscript-layout`. The geometry/text `Core` and the sequence\nengine, each built on the `Projection` contract — turn a structural input\ninto a positioned output under tunable metrics. The sequence engine is the\nonly one implemented here: C4 placement is delegated to `dot` (the layered\nengine), which `emit` drives directly; a flowchart engine is a planned\nextension point on the same core, not yet built.","text":"","module":"layout","href":"module/layout.html#layout-Layout"},{"fqn":"layout::Message","name":"Message","kind":"data","summary":"A message between two lifelines: its source and target ids (equal for a\nself-message), kind, primary label (method name or return marker), and the\ndimmed detail after it (a call signature or return type). `source` is the\nwire field `from`, renamed because `from` is a PseudoScript keyword.","text":"","module":"layout","href":"module/layout.html#layout-Message"},{"fqn":"layout::MessageItem","name":"MessageItem","kind":"data","summary":"","text":"","module":"layout","href":"module/layout.html#layout-MessageItem"},{"fqn":"layout::Metrics","name":"Metrics","kind":"data","summary":"Tunable spacing and font metrics for the sequence engine — head-card sizing,\nrow advance per message kind, fragment padding. Field detail is the engine's\nconcern; the defaults are the one source of truth consumers start from.","text":"","module":"layout","href":"module/layout.html#layout-Metrics"},{"fqn":"layout::MsgKind","name":"MsgKind","kind":"data","summary":"The kind of a sequence message: a call to another lifeline, a return to the\ncaller, or a self-message on the sender's own lifeline.","text":"","module":"layout","href":"module/layout.html#layout-MsgKind"},{"fqn":"layout::Participant","name":"Participant","kind":"data","summary":"One lifeline: its id (FQN), display label, C4 kind for the head card, optional\nsummary, and the ancestry path shown under the name for container/component\nlifelines.","text":"","module":"layout","href":"module/layout.html#layout-Participant"},{"fqn":"layout::PlacedFragment","name":"PlacedFragment","kind":"data","summary":"A placed fragment frame: its box, the operator-tab label (the first section's\nguard), and the dividers splitting later sections.","text":"","module":"layout","href":"module/layout.html#layout-PlacedFragment"},{"fqn":"layout::PlacedMessage","name":"PlacedMessage","kind":"data","summary":"A placed message: its kind, source/target ids, endpoint x-positions, row y,\ndirection (+1 left-to-right, -1 right-to-left), reading-order step, label, and\ndetail.","text":"","module":"layout","href":"module/layout.html#layout-PlacedMessage"},{"fqn":"layout::PlacedParticipant","name":"PlacedParticipant","kind":"data","summary":"A placed lifeline: its id, label, kind, ancestry path, wrapped summary lines,\nhead-card rectangle, the lifeline's centre x, and the y span of its dashed\nline.","text":"","module":"layout","href":"module/layout.html#layout-PlacedParticipant"},{"fqn":"layout::Point","name":"Point","kind":"data","summary":"A point in renderer coordinates.","text":"","module":"layout","href":"module/layout.html#layout-Point"},{"fqn":"layout::Rect","name":"Rect","kind":"data","summary":"An axis-aligned rectangle: its top-left corner and extent.","text":"","module":"layout","href":"module/layout.html#layout-Rect"},{"fqn":"layout::Section","name":"Section","kind":"data","summary":"One compartment of a fragment: its guard label (shown in the operator tab or\nbeside a divider) over a body of items.","text":"","module":"layout","href":"module/layout.html#layout-Section"},{"fqn":"layout::Sequence","name":"Sequence","kind":"component","summary":"The sequence engine: lays a structural `Diagram` out into a `SequenceLayout` —\nlifeline x-positions in first-appearance order, message rows stacked by\nevaluation order, and fragment frames sized to their bodies. The only engine\nimplemented in this crate; C4 placement is `dot`'s job (`emit` drives it), and\na flowchart engine would follow the same `Projection` contract.","text":"","module":"layout","href":"module/layout.html#layout-Sequence"},{"fqn":"layout::SequenceLayout","name":"SequenceLayout","kind":"data","summary":"A laid-out sequence diagram: the canvas size plus every participant, message,\nactivation bar, and fragment placed at absolute coordinates the renderer draws\nverbatim. The sequence engine's output.","text":"","module":"layout","href":"module/layout.html#layout-SequenceLayout"},{"fqn":"layout::Size","name":"Size","kind":"data","summary":"A width/height extent.","text":"","module":"layout","href":"module/layout.html#layout-Size"},{"fqn":"lsp","name":"lsp","kind":"module","summary":"","text":"","module":"lsp","href":"module/lsp.html"},{"fqn":"lsp::DefTarget","name":"DefTarget","kind":"data","summary":"A go-to-definition target straight from `lsp_core`: the FQN of the module the\ndefinition lives in, and its span within that module's source. The server maps\n`fqn` to a file URI — the target file, not the file the request came from.","text":"","module":"lsp","href":"module/lsp.html#lsp-DefTarget"},{"fqn":"lsp::Lsp","name":"Lsp","kind":"container","summary":"`crates/pseudoscript-lsp`. The stdio language server (tower-lsp): workspace\ndiagnostics on change, and hover, definition, completion, references, rename,\nsemantic tokens, symbols, folding, and formatting — every language answer\ndelegated to `lsp_core`. Owns the transport, the document store, and the\nURI↔FQN mapping, nothing more.","text":"","module":"lsp","href":"module/lsp.html#lsp-Lsp"},{"fqn":"lsp::Occurrence","name":"Occurrence","kind":"data","summary":"One resolved editor location: the file URI a target FQN maps back to, and the\nrange within it. The server's transport-level mapping of a `lsp_core` answer.","text":"","module":"lsp","href":"module/lsp.html#lsp-Occurrence"},{"fqn":"lsp::OpenDocument","name":"OpenDocument","kind":"data","summary":"One open editor buffer: its document URI, current source text, and the\neditor's version counter. The buffer overlays on-disk text until closed.","text":"","module":"lsp","href":"module/lsp.html#lsp-OpenDocument"},{"fqn":"lsp::Server","name":"Server","kind":"component","summary":"The tower-lsp `Backend`: owns the stdio transport, the document store, the\nserver lifecycle, and request routing. Holds no language logic — it locks the\nstore, hands the active text and the resolved workspace to a `lsp_core`\nhandler, and maps the result back to file locations.","text":"","module":"lsp","href":"module/lsp.html#lsp-Server"},{"fqn":"lsp::Store","name":"Store","kind":"component","summary":"The workspace document store: the server's own filesystem edge. Discovers the\nproject root (`pds.toml`, §8.1) by walking up from the opened URI, walks the\ntree for every visible `.pds` file, derives each module's FQN from its path,\nand overlays open buffers on disk text. Caches each parse and memoises the\nresolved `model::Workspace` — built from the local parses with the workspace's\ndirect-dependency externals bound (§8.3) — both invalidated on any edit. The\nexternals are cached separately and reload only on a dependency change.","text":"","module":"lsp","href":"module/lsp.html#lsp-Store"},{"fqn":"lsp_core","name":"lsp_core","kind":"module","summary":"","text":"","module":"lsp_core","href":"module/lsp_core.html"},{"fqn":"lsp_core::Analysis","name":"Analysis","kind":"component","summary":"Document-level analysis: parse-and-check diagnostics, Markdown hover for the\nsymbol under the caret (falling back to an inferred type), go-to-definition,\ninlay hints, and the canonical format edit. Resolution is delegated to\n`model`; this maps the result into LSP shapes.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Analysis"},{"fqn":"lsp_core::Complete","name":"Complete","kind":"component","summary":"Completion: the candidates offered at a byte offset, resolved across the\nworkspace and its externals. A `.`/`::` boundary drives member and path\ncompletion.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Complete"},{"fqn":"lsp_core::CompletionItem","name":"CompletionItem","kind":"data","summary":"One completion candidate: the inserted label, the integer LSP\n`CompletionItemKind`, and detail text.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-CompletionItem"},{"fqn":"lsp_core::Convert","name":"Convert","kind":"component","summary":"Position conversion: the single home for mapping between byte offsets and\nUTF-16 line/character positions, so every handler agrees on coordinates.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Convert"},{"fqn":"lsp_core::DefTarget","name":"DefTarget","kind":"data","summary":"A go-to-definition target: the FQN of the module the definition lives in and\nthe byte span of the definition within that module's source. The consuming\nedge maps `fqn` to a file URI and converts `span` to an editor range against\n*that* file's text — `lsp_core` returns the byte span, not a `Range`, because\nit does not hold the target module's source to convert against.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-DefTarget"},{"fqn":"lsp_core::Diagnostic","name":"Diagnostic","kind":"data","summary":"One diagnostic mapped to LSP shape: its range, severity, message, optional\ncode, and the code's article URL (`codeDescription`, the editor's clickable\nlink — empty when the code carries no article). Converted from the\nparser/checker's byte-span diagnostics; the code and its URL pass through\nunchanged.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Diagnostic"},{"fqn":"lsp_core::Hover","name":"Hover","kind":"data","summary":"Markdown hover content the editor renders in a tooltip.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Hover"},{"fqn":"lsp_core::LspCore","name":"LspCore","kind":"container","summary":"`crates/pseudoscript-lsp-core`. The single home for language intelligence as\ntransport-neutral handlers — the same logic the stdio server and the browser\nwasm both call.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-LspCore"},{"fqn":"lsp_core::Position","name":"Position","kind":"data","summary":"A zero-based caret position: line and UTF-16 character offset within the\nline. This and the shapes below model the standalone `lsp_types` vocabulary\nthe crate returns (pinned to the version tower-lsp re-exports, wasm-safe),\nso the server edge passes values through with no conversion.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Position"},{"fqn":"lsp_core::Range","name":"Range","kind":"data","summary":"A half-open text range between two positions.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Range"},{"fqn":"lsp_core::Refs","name":"Refs","kind":"component","summary":"References and rename: every occurrence of the symbol under the caret across\nthe workspace, the document highlights for it, and the workspace-wide rename\nedits.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Refs"},{"fqn":"lsp_core::Semantic","name":"Semantic","kind":"component","summary":"Semantic tokens: AST-aware highlighting that colours each token by its\ndeclared role, plus the legend the editor binds.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Semantic"},{"fqn":"lsp_core::Symbols","name":"Symbols","kind":"component","summary":"Document and workspace structure: the outline symbols, the foldable ranges,\nand the workspace-wide symbol query.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-Symbols"},{"fqn":"lsp_core::TextEdit","name":"TextEdit","kind":"data","summary":"A text edit: replace `range` with `newText`. Formatting and rename return\nthese.","text":"","module":"lsp_core","href":"module/lsp_core.html#lsp-core-TextEdit"},{"fqn":"model","name":"model","kind":"module","summary":"","text":"","module":"model","href":"module/model.html"},{"fqn":"model::Alt","name":"Alt","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Alt"},{"fqn":"model::ArchRule","name":"ArchRule","kind":"data","summary":"One architectural-principle lint rule (LANG.md §9 — the C4 facade/boundary\nprinciples). `code` is its stable identifier (`PDS-ARCH-001`); `slug` is the\nfilename of the article documenting it under the published principles base\nURL. Every firing is a `Warning` — a violation advises rather than\ninvalidates — so the rule carries no severity of its own.","text":"","module":"model","href":"module/model.html#model-ArchRule"},{"fqn":"model::Architecture","name":"Architecture","kind":"component","summary":"LANG.md §9 — architectural-principle lints over the resolved graph. Beyond §8.2\nvisibility (which a `public` component still satisfies), these advise on C4\nstructure: a cross-module call SHOULD reach a container/system's published face,\nnot an internal `component` (Facade/Gateway); the module dependency graph SHOULD\nstay acyclic; a cross-system call SHOULD couple to the other system's boundary,\nnot its containers; a `component` SHOULD have a `for` container, not stand alone\n(redundant with a container). Each firing is a `Warning` stamped with the rule's\n`code` and `codeDescription` (its article URL); the model stays valid.","text":"","module":"model","href":"module/model.html#model-Architecture"},{"fqn":"model::Branch","name":"Branch","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Branch"},{"fqn":"model::Builder","name":"Builder","kind":"component","summary":"Projects the parsed, resolved workspace into the architecture graph: structural\nnodes plus edges from `for` parents, body calls, triggers, and `from`\nprovenance, with a sequence trace recorded per disclosed body. A pure\nprojection — no I/O — so the emit crate and a future salsa/LSP layer can both\nadopt it.","text":"","module":"model","href":"module/model.html#model-Builder"},{"fqn":"model::Call","name":"Call","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Call"},{"fqn":"model::CaretResolve","name":"CaretResolve","kind":"component","summary":"Caret resolution — the engine every cursor feature shares (`lsp_core` hover,\ndefinition, references, rename; the IDE's symbol actions). Tokenizes the\nactive source, finds the identifier under the offset, and resolves it across\nthe workspace and its externals: a node or data FQN, a same-node call or member access,\nor a local reference. Token-level, so it survives a partial parse.","text":"","module":"model","href":"module/model.html#model-CaretResolve"},{"fqn":"model::Checks","name":"Checks","kind":"component","summary":"Static analysis (LANG.md §2.2, §2.3, §2.4, §3.3, §3.4, §3.5, §4, §5.1, §5.2, §6,\n§7, §8): builds the symbol tables, then runs the well-formedness checks. Every\nentry returns a `syntax::Diagnostic[]`; well-formed input yields an empty one.\nChecks are conservative — each rule fires only when the violation is certain.","text":"","module":"model","href":"module/model.html#model-Checks"},{"fqn":"model::Commit","name":"Commit","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Commit"},{"fqn":"model::Completion","name":"Completion","kind":"component","summary":"Context-aware completion (the model-native producer `lsp_core` maps to LSP\nitems): candidates at a caret offset resolved across the workspace and its\nexternals — members after `.`, a module's public symbols after `::`, the\nbuilt-in macros after `#[`, types in type position, else keywords and symbols.","text":"","module":"model","href":"module/model.html#model-Completion"},{"fqn":"model::ConstantType","name":"ConstantType","kind":"data","summary":"One `constant`'s FQN paired with its declared primitive type name (§3.6,\nADR-039), so inference resolves a `module::NAME` reference to its type.","text":"","module":"model","href":"module/model.html#model-ConstantType"},{"fqn":"model::CrossModule","name":"CrossModule","kind":"component","summary":"§8.2 — cross-module visibility resolution. Walks each module's qualified\nreferences — `for` parents, type annotations (field, parameter, return, and\ngeneric-argument types), feature targets, body call targets, value-position\nunion-variant references, and the member named after a call target's FQN — and\nagainst the global FQN index enforces: a reference from module A to a node in\nmodule B resolves only if that node is `public`. A private target or a dangling\ncross-module FQN is a diagnostic. Same-module references are the single-module\nchecks' business and are skipped here.","text":"","module":"model","href":"module/model.html#model-CrossModule"},{"fqn":"model::DataField","name":"DataField","kind":"data","summary":"One field of a `data` record or union-variant record: its name and rendered\ntype.","text":"","module":"model","href":"module/model.html#model-DataField"},{"fqn":"model::DataShape","name":"DataShape","kind":"data","summary":"The disclosed shape of a `data` node (§3.4, §3.5): a record of fields, a\ndiscriminated union of variants, or an undisclosed black box. Carried on a\n`data` `GraphNode` so the entity (ER) view draws the rows without re-reading\nsource.","text":"","module":"model","href":"module/model.html#model-DataShape"},{"fqn":"model::DataVariant","name":"DataVariant","kind":"data","summary":"One variant of a `data` union (§3.5): its name and, for a record variant, its\nfields.","text":"","module":"model","href":"module/model.html#model-DataVariant"},{"fqn":"model::DepError","name":"DepError","kind":"data","summary":"Why parsing a manifest's `[dependencies]` table or a `pds.lock` failed: the\noffending entry and a human-readable message. Malformed TOML, an unknown key,\nor more than one of tag/rev/branch on one dependency (§8.3).","text":"","module":"model","href":"module/model.html#model-DepError"},{"fqn":"model::DepFile","name":"DepFile","kind":"data","summary":"One dependency module's in-memory form: its FQN *within* the dependency\nworkspace (path relative to that workspace root) and its source. The resolver\nprefixes it with the dependency name.","text":"","module":"model","href":"module/model.html#model-DepFile"},{"fqn":"model::DepSpec","name":"DepSpec","kind":"data","summary":"A `[dependencies]` entry as written in `pds.toml` (§8.3): a git URL with at\nmost one of tag/rev/branch and an in-repo sub-path, or a local sibling path.\nEmpty strings stand for the absent options.","text":"","module":"model","href":"module/model.html#model-DepSpec"},{"fqn":"model::Deps","name":"Deps","kind":"component","summary":"§8.3 — the dependency resolver. Parses a manifest's `[dependencies]` and a\n`pds.lock`, then maps each direct dependency to its dependency-name-prefixed\nmodules — the externals the checker binds for cross-workspace resolution. The\nsingle source of the slug→name→`dep::module` mapping, shared by the native\nloader (`project`) and the WASM bridge (`ide`). Pure: fetching and disk are\nthe caller's job.","text":"","module":"model","href":"module/model.html#model-Deps"},{"fqn":"model::Edge","name":"Edge","kind":"data","summary":"A typed, directed relationship between two graph node FQNs. `source` is the\nwire field `from` — `from` is a PseudoScript keyword, so the model renames\nit. Either endpoint may name a node not present as a `GraphNode` — a\nsynthesised trigger initiator, or a target that does not resolve. `label` is\nthe method name for `Call`, otherwise empty. `span` is the source range that\nproduced the edge — the call site for a `Call` — so an architectural lint can\npoint its diagnostic at the offending call; the empty span when the edge is\nsynthesised.","text":"","module":"model","href":"module/model.html#model-Edge"},{"fqn":"model::EdgeKind","name":"EdgeKind","kind":"data","summary":"What relationship a graph edge expresses (LANG.md §9.1): a `for` parent link,\na body call (label = method), a synthesised trigger initiator edge, or a\n`from` provenance link.","text":"","module":"model","href":"module/model.html#model-EdgeKind"},{"fqn":"model::FeatureCheck","name":"FeatureCheck","kind":"component","summary":"§5.2 / §8.1 — feature checks. A feature's `for` target MUST resolve to a node,\nnot a type or module; a target this single-module model cannot see is left to\ncross-module resolution. Feature names occupy their own module namespace, so a\nrepeated name is a collision (checked once per module).","text":"","module":"model","href":"module/model.html#model-FeatureCheck"},{"fqn":"model::FieldlessVariants","name":"FieldlessVariants","kind":"data","summary":"A union's fieldless variant names, keyed by the union's bare name (§3.5).\nFieldless variants do not hoist a symbol — they are addressed\n`module::Union::Variant` (ADR-032) — so they index under their union.","text":"","module":"model","href":"module/model.html#model-FieldlessVariants"},{"fqn":"model::Folding","name":"Folding","kind":"component","summary":"The foldable regions of a module: every multi-line disclosed declaration and\nstatement block, and doc-comment runs.","text":"","module":"model","href":"module/model.html#model-Folding"},{"fqn":"model::Git","name":"Git","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Git"},{"fqn":"model::Graph","name":"Graph","kind":"data","summary":"The resolved architecture graph: every node and typed edge across all C4\nlevels, plus feature scenarios. The single source every view projects from —\nenough to extract any view without re-reading source. Per-callable sequence\ntraces (`Step[]`) are held alongside, keyed by the owning callable's FQN.","text":"","module":"model","href":"module/model.html#model-Graph"},{"fqn":"model::GraphNode","name":"GraphNode","kind":"data","summary":"One node in the resolved graph — a structural declaration, a `data` type, or a\ncallable. Carries its FQN, simple name, kind, enclosing-node FQN (`for` parent,\nowning node, or empty at top level), declaring module, visibility, name span,\nany trigger macros (callables only), the call signature (callables only), the\ndisclosed shape (`data` only), and lifted `///` documentation.","text":"","module":"model","href":"module/model.html#model-GraphNode"},{"fqn":"model::Inference","name":"Inference","kind":"component","summary":"Local-binding type inference, for inlay hints and hover. Assignments are\nuntyped (`x = expr`); this infers each binding's type from its right-hand side\n— a call's return type, a field access, a `from` expression, or a literal.\nBest-effort: an un-typeable expression yields nothing rather than a guess.","text":"","module":"model","href":"module/model.html#model-Inference"},{"fqn":"model::Local","name":"Local","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Local"},{"fqn":"model::Lock","name":"Lock","kind":"data","summary":"A parsed `pds.lock` (§8.4): the pinned dependency graph. A black box here — its\nshape is the lockfile's concern, not the model's.","text":"","module":"model","href":"module/model.html#model-Lock"},{"fqn":"model::Loop","name":"Loop","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Loop"},{"fqn":"model::MacroTargeting","name":"MacroTargeting","kind":"component","summary":"§2.4 / ADR-015 — macro targeting. Every built-in macro (`onevent`, `schedule`,\n`http`, `manual`) targets callables; on any structural declaration it is a\nwrong-target error, and an unrecognised macro is unknown. An `#[onevent(E)]`\nhandler MUST have exactly one parameter whose type matches the event type.","text":"","module":"model","href":"module/model.html#model-MacroTargeting"},{"fqn":"model::Member","name":"Member","kind":"data","summary":"A member reachable through `.` from a node or `data` owner: its name, kind,\ndefinition span, one-line signature detail (`run(name: string): uuid`), value\ntype (a field's type or a callable's return type), the ordered parameter\ntypes (empty for a field — their count is the call arity, ADR-022), the\n`///` summary (absent for a field — the grammar has no field doc), and\nwhether it is `public` (callables only; gates cross-module member completion,\n§8.2). Powers member completion, arity checks, and go-to-definition.","text":"","module":"model","href":"module/model.html#model-Member"},{"fqn":"model::MemberKind","name":"MemberKind","kind":"data","summary":"What kind of member is reachable through `.` from an owner: a node's callable\n(§5.1) or a `data` record field (§3.4).","text":"","module":"model","href":"module/model.html#model-MemberKind"},{"fqn":"model::Model","name":"Model","kind":"container","summary":"`crates/pseudoscript-model`. AST to one resolved graph; static checks\n(resolution, visibility, Result flow, return coverage); the §8.3 dependency\nresolver; and the LSP analysis primitives (completion, folding, semantic\ntokens, inference). WASM-safe.","text":"","module":"model","href":"module/model.html#model-Model"},{"fqn":"model::ModuleDiagnostics","name":"ModuleDiagnostics","kind":"data","summary":"One workspace module's diagnostics, attributed to its FQN. Every span lies in\nthat module's own source, so a tool with the FQN-to-file mapping publishes\neach list against the right file.","text":"","module":"model","href":"module/model.html#model-ModuleDiagnostics"},{"fqn":"model::ModuleEntry","name":"ModuleEntry","kind":"data","summary":"One module's parsed AST, resolved symbol table, and FQN, as held by a\n`Workspace`.","text":"","module":"model","href":"module/model.html#model-ModuleEntry"},{"fqn":"model::NodeDoc","name":"NodeDoc","kind":"data","summary":"A node's documentation, lifted from its `///` block (LANG.md §2.1): the\nsummary (compact-diagram text), the extended description (tooltip text), and\nits tags (`\n`, including the `#`), in source order.","text":"","module":"model","href":"module/model.html#model-NodeDoc"},{"fqn":"model::NodeKind","name":"NodeKind","kind":"data","summary":"What kind of model element a `GraphNode` is. Adds `Callable` to the structural\nkinds: structural declarations, `data` types (including hoisted union\nvariants), and callables all become nodes.","text":"","module":"model","href":"module/model.html#model-NodeKind"},{"fqn":"model::OnEvent","name":"OnEvent","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-OnEvent"},{"fqn":"model::PackageId","name":"PackageId","kind":"data","summary":"A content-addressable package identity: its source, resolved revision, and\nin-repo path. Drives the `pds_modules/` slug a git package materialises into.","text":"","module":"model","href":"module/model.html#model-PackageId"},{"fqn":"model::ParentKind","name":"ParentKind","kind":"component","summary":"§4 / ADR-010 — C4 parent-kind well-formedness. A `for` parent links a node to\nits enclosing level, and the levels MUST nest: a `container` parents a\n`system`, a `component` parents a `container`. A parent of the wrong kind is a\ndiagnostic (`container `X` parent `Y` is not a system`). A bare parent that\nnames no same-module node is unresolved (§8.1); a qualified parent this\nsingle-module model cannot see is left to cross-module resolution.","text":"","module":"model","href":"module/model.html#model-ParentKind"},{"fqn":"model::Private","name":"Private","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Private"},{"fqn":"model::Public","name":"Public","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Public"},{"fqn":"model::Record","name":"Record","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Record"},{"fqn":"model::ReservedNames","name":"ReservedNames","kind":"component","summary":"§2.3 / ADR-012 — reserved-word identifiers. A declared identifier MUST NOT be a\nreserved word: a keyword, a primitive type name, or `Result`/`Option`. Covers\nevery name a module declares — `data`, node, callable, field, parameter,\nvariant, and feature names — so `data string` or a parameter named `Result` is\na diagnostic.","text":"","module":"model","href":"module/model.html#model-ReservedNames"},{"fqn":"model::Resolution","name":"Resolution","kind":"data","summary":"The outcome of resolving a cross-module reference (LANG.md §8.2): the FQN\nnames a public symbol, a private one reached from another module, or nothing.","text":"","module":"model","href":"module/model.html#model-Resolution"},{"fqn":"model::ResolveHit","name":"ResolveHit","kind":"data","summary":"One resolved caret hit: the clicked identifier's span, the defining module\nand the definition's span there, the resolved graph FQN (a member resolves to\n`owner::member` — the key `emit`'s symbol projection uses), a Markdown title\nline, and the doc summary or signature detail shown under it.","text":"","module":"model","href":"module/model.html#model-ResolveHit"},{"fqn":"model::Resolver","name":"Resolver","kind":"component","summary":"Resolves a module's declarations into a symbol table (LANG.md §8). FQNs are\nfile-derived: a single `.pds` file is one module, named by its `//!` path.\nHolds two namespaces — type names and node names share the symbol table, while\nfeature names live in a separate namespace the `Checks` enforce — plus the\nmember, fieldless-variant, and constant-type indexes. The LSP reuses the\ntable for hover and go-to-definition.","text":"","module":"model","href":"module/model.html#model-Resolver"},{"fqn":"model::ResultFlow","name":"ResultFlow","kind":"component","summary":"§6 — flow-sensitive `Result` / `Option` typestate. Each binding carries a\nstate (`Unknown`, `Ok`/`Err` for a `Result`, `Some`/`None` for an `Option`),\nnarrowed on entering the branches of `if (r.isErr)` / `if (r.isOk)` /\n`if (o.isNone)` / `if (o.isSome)`. Reading `.value` while known-`Err` or\nknown-`None`, or `.error` while known-`Ok`, is a model error. The env is\ncloned per branch so narrowing does not leak; an `if` whose guarded arm\ndiverges narrows the fall-through to the inverse state (`Ok`<->`Err`,\n`Some`<->`None`).","text":"","module":"model","href":"module/model.html#model-ResultFlow"},{"fqn":"model::Return","name":"Return","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Return"},{"fqn":"model::ReturnCoverage","name":"ReturnCoverage","kind":"component","summary":"ADR-016 — return coverage. A disclosed non-void callable MUST return on every\npath. A `return` makes a block diverge; an `if`/`else` diverges only when both\narms do; `for`/`while` bodies and bare expressions never guarantee a return.\nAn explicit `void` and a parse-recovered missing return type (ADR-040) both\nmean void.","text":"","module":"model","href":"module/model.html#model-ReturnCoverage"},{"fqn":"model::Rev","name":"Rev","kind":"data","summary":"A resolved revision selector — at most one of these (§8.3); `Default` is the\nremote's default-branch HEAD.","text":"","module":"model","href":"module/model.html#model-Rev"},{"fqn":"model::Scenario","name":"Scenario","kind":"data","summary":"A `feature` BDD scenario attached to its target node (LANG.md §5.2, §9.3):\nits name, the canonicalised target FQN (as written if it does not resolve),\nthe declaring module's FQN, the span of the feature name (a host's\ngo-to-definition target), lifted `///` documentation, and the ordered\ngiven/when/then steps. Steps are prose, not resolved, so a scenario adds no\nedges; it renders as a card on its target node's doc page.","text":"","module":"model","href":"module/model.html#model-Scenario"},{"fqn":"model::ScenarioStep","name":"ScenarioStep","kind":"data","summary":"One step of a `Scenario` (LANG.md §5.2): a keyword (`given`/`when`/`then`/\n`and`/`but`) and its prose, with the string literal's quotes stripped.","text":"","module":"model","href":"module/model.html#model-ScenarioStep"},{"fqn":"model::SelfCall","name":"SelfCall","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-SelfCall"},{"fqn":"model::Semantic","name":"Semantic","kind":"component","summary":"AST-aware semantic colouring: each identifier classified by its declared role\n(node→namespace, `data`→class, callable→method, parameter, call segment), the\nspans `lsp_core` delta-encodes for the editor.","text":"","module":"model","href":"module/model.html#model-Semantic"},{"fqn":"model::SigParam","name":"SigParam","kind":"data","summary":"One parameter of a callable signature: its name and rendered type.","text":"","module":"model","href":"module/model.html#model-SigParam"},{"fqn":"model::Signature","name":"Signature","kind":"data","summary":"A callable node's signature (§5.1): its ordered parameters and rendered return\ntype. Carried on a callable `GraphNode` so the sequence and symbol views can\nshow the call shape without re-reading source.","text":"","module":"model","href":"module/model.html#model-Signature"},{"fqn":"model::Source","name":"Source","kind":"data","summary":"The resolved source of a dependency (ADR-026): a fetched git repository at a\nrevision and in-repo sub-path, or a local sibling workspace read from disk.","text":"","module":"model","href":"module/model.html#model-Source"},{"fqn":"model::Step","name":"Step","kind":"data","summary":"One step in a callable's ordered sequence trace (LANG.md §7, §9.2). Calls in a\nchained expression are emitted left-to-right; control flow becomes `Alt`/\n`Loop` frames whose bodies are nested step lists, in §7 evaluation order.","text":"","module":"model","href":"module/model.html#model-Step"},{"fqn":"model::Symbol","name":"Symbol","kind":"data","summary":"One declared, addressable node in a module namespace: the bare name, its FQN\n(`module::Ledger`), its declaration kind, whether it is `public` (§8.2), and\nthe span of its name.","text":"","module":"model","href":"module/model.html#model-Symbol"},{"fqn":"model::SymbolKind","name":"SymbolKind","kind":"data","summary":"The lowercase declaration keyword a `Symbol` names. Drives the parent-kind and\nmacro-target diagnostics, which embed it as prose. `Constant` is a top-level\nprimitive value (§3.6, ADR-039).","text":"","module":"model","href":"module/model.html#model-SymbolKind"},{"fqn":"model::SymbolTable","name":"SymbolTable","kind":"data","summary":"One module's resolved symbol table (LANG.md §8): its FQN plus the declared\nnodes, the members reachable through `.`, the fieldless-variant index\n(ADR-032), and the constant-type index (ADR-039). The `Resolver` produces it;\nthe `Workspace` indexes and the `Checks` consume it.","text":"","module":"model","href":"module/model.html#model-SymbolTable"},{"fqn":"model::Tag","name":"Tag","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Tag"},{"fqn":"model::Trigger","name":"Trigger","kind":"data","summary":"A trigger macro on a callable (LANG.md §2.4): the macro that makes the\ncallable a diagram entry point and synthesises an inbound initiator edge. Each\nvariant maps to a synthesised initiator node (`event:<FQN>`, `scheduler`,\n`client`, `caller`).","text":"","module":"model","href":"module/model.html#model-Trigger"},{"fqn":"model::TypeRefs","name":"TypeRefs","kind":"component","summary":"§3.3 / §8.1 — type-reference resolution. Every named type in a declaration — a\nfield, parameter, or return type, and each generic argument — MUST resolve. A\nbare name that resolves to nothing is reported as unresolved; a name that\nresolves to a declared type or node MUST be written by its full FQN\n(`module::Name`), so an unqualified declared-type annotation is rejected.\nBuilt-in types (the primitives, `Result`, `Option`) stay bare.","text":"","module":"model","href":"module/model.html#model-TypeRefs"},{"fqn":"model::Union","name":"Union","kind":"data","summary":"","text":"","module":"model","href":"module/model.html#model-Union"},{"fqn":"model::VariantCollision","name":"VariantCollision","kind":"component","summary":"§3.5 / ADR-006 — union variant collision. A top-level `data Name` followed by\nan inline variant `| Name { ... }` hoisting the same name is a collision. Bare\nvariants reference existing data and never collide.","text":"","module":"model","href":"module/model.html#model-VariantCollision"},{"fqn":"model::Visibility","name":"Visibility","kind":"data","summary":"Whether a node is `public` (cross-module addressable) or module-private\n(LANG.md §8.2).","text":"","module":"model","href":"module/model.html#model-Visibility"},{"fqn":"model::Workspace","name":"Workspace","kind":"component","summary":"The resolved set of modules keyed by FQN (LANG.md §8). Built once per\nworkspace from `(fqn, parsed module)` pairs; owns the per-module models and a\nglobal FQN-to-`Symbol` index for cross-module resolution.","text":"","module":"model","href":"module/model.html#model-Workspace"},{"fqn":"model::WorkspaceModule","name":"WorkspaceModule","kind":"data","summary":"One `.pds` module of a workspace: its caller-supplied FQN (the loader derives\nit from the file path relative to `pds.toml`, LANG.md §8.1) and its source\ntext. This crate stays pure over in-memory modules; it never touches the\nfilesystem.","text":"","module":"model","href":"module/model.html#model-WorkspaceModule"},{"fqn":"project","name":"project","kind":"module","summary":"","text":"","module":"project","href":"module/project.html"},{"fqn":"project::Deps","name":"Deps","kind":"component","summary":"Resolves a workspace's declared dependencies into modules the checker binds as\nexternals (§8.3): reads `pds.lock` + `pds_modules/`, materialises each direct\ndependency's `.pds` modules under its dependency-name prefix, and resolves a\nlocal path dependency's directory.","text":"","module":"project","href":"module/project.html#project-Deps"},{"fqn":"project::IoError","name":"IoError","kind":"data","summary":"A filesystem failure surfaced to the caller: the path or manifest that could\nnot be read, with a human-readable message.","text":"","module":"project","href":"module/project.html#project-IoError"},{"fqn":"project::Loader","name":"Loader","kind":"component","summary":"Resolves and reads a workspace off disk: finds the root by walking up to the\nnearest `pds.toml`, then walks the tree for visible `.pds` files and loads each\nas a `(fqn, source)` module — mapping its path to a flat module FQN (§8.1) and\nskipping `target/` and `pds_modules/`.","text":"","module":"project","href":"module/project.html#project-Loader"},{"fqn":"project::Project","name":"Project","kind":"container","summary":"`crates/pseudoscript-project`. The disk-facing loader: resolves the workspace\nroot, reads its `.pds` modules, and materialises dependency modules from the\nvendor directory. The only place the native toolchain touches the filesystem\nfor project loading.","text":"","module":"project","href":"module/project.html#project-Project"},{"fqn":"syntax","name":"syntax","kind":"module","summary":"","text":"","module":"syntax","href":"module/syntax.html"},{"fqn":"syntax::Assign","name":"Assign","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Assign"},{"fqn":"syntax::BinOp","name":"BinOp","kind":"data","summary":"A binary operator (§7.5): arithmetic, comparison, equality, and boolean.","text":"","module":"syntax","href":"module/syntax.html#syntax-BinOp"},{"fqn":"syntax::Binary","name":"Binary","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Binary"},{"fqn":"syntax::BlankLines","name":"BlankLines","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-BlankLines"},{"fqn":"syntax::Block","name":"Block","kind":"data","summary":"A `{ ... }` statement block (§7): statements in order, plus the brace span.","text":"","module":"syntax","href":"module/syntax.html#syntax-Block"},{"fqn":"syntax::BlockComment","name":"BlockComment","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-BlockComment"},{"fqn":"syntax::BodyMember","name":"BodyMember","kind":"data","summary":"A member of a disclosed node body: a callable, or — under error recovery —\na nested structural declaration the parser flags as illegal (ADR-011).","text":"","module":"syntax","href":"module/syntax.html#syntax-BodyMember"},{"fqn":"syntax::BoolLit","name":"BoolLit","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-BoolLit"},{"fqn":"syntax::CallableDecl","name":"CallableDecl","kind":"data","summary":"A callable (implicit operation) declared inside a disclosed node (§5.1).\n`returnTy` is required (ADR-040) — a missing return type is a syntax error,\nrecovered as `void`; `body` absent means a black box (`;`).","text":"","module":"syntax","href":"module/syntax.html#syntax-CallableDecl"},{"fqn":"syntax::CallableMember","name":"CallableMember","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-CallableMember"},{"fqn":"syntax::Compose","name":"Compose","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Compose"},{"fqn":"syntax::Constant","name":"Constant","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Constant"},{"fqn":"syntax::ConstantDecl","name":"ConstantDecl","kind":"data","summary":"A `constant NAME = Literal` declaration (§3.6, ADR-039): a top-level primitive\nvalue. `public` lives on the enclosing `Declaration`, mirroring `data`.","text":"","module":"syntax","href":"module/syntax.html#syntax-ConstantDecl"},{"fqn":"syntax::Convert","name":"Convert","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Convert"},{"fqn":"syntax::Data","name":"Data","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Data"},{"fqn":"syntax::DataBody","name":"DataBody","kind":"data","summary":"The three `data` forms. A bare `| Name` variant is an enum case; a\n`| Name { .. }` variant carries an inline record (§3.5, ADR-006).","text":"","module":"syntax","href":"module/syntax.html#syntax-DataBody"},{"fqn":"syntax::DataDecl","name":"DataDecl","kind":"data","summary":"A `data` declaration: a record, a union, or a black box (§3.4, §3.5).","text":"","module":"syntax","href":"module/syntax.html#syntax-DataDecl"},{"fqn":"syntax::DeclItem","name":"DeclItem","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-DeclItem"},{"fqn":"syntax::DeclKind","name":"DeclKind","kind":"data","summary":"The structural payload of a declaration: a node (person/system/container/\ncomponent), a `data` type, or a top-level `constant` (§3.6, ADR-039).","text":"","module":"syntax","href":"module/syntax.html#syntax-DeclKind"},{"fqn":"syntax::DeclMember","name":"DeclMember","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-DeclMember"},{"fqn":"syntax::Declaration","name":"Declaration","kind":"data","summary":"A documented, annotated structural declaration (§4): the shared\n`doc → macros → public` prefix plus the structural payload.","text":"","module":"syntax","href":"module/syntax.html#syntax-Declaration"},{"fqn":"syntax::Diagnostic","name":"Diagnostic","kind":"data","summary":"One message about a span of source. The single diagnostic type every crate\nemits, so a driver collects lexer, parser, and checker output into one\nordered list. `code` is an optional stable identifier (e.g. `E0001`) for\ntooling; the human-facing text is `message`. `codeDescription` is an optional\nURL the code resolves to — an article explaining the rule — which the LSP\nsurfaces as the diagnostic's clickable link. Empty when the code carries no\narticle.","text":"","module":"syntax","href":"module/syntax.html#syntax-Diagnostic"},{"fqn":"syntax::DocBlock","name":"DocBlock","kind":"data","summary":"A `///` doc block split into summary and extended on the first blank `///`\nline (ADR-009): summary feeds compact diagrams, extended feeds tooltips,\ntags carry the `\n` markers.","text":"","module":"syntax","href":"module/syntax.html#syntax-DocBlock"},{"fqn":"syntax::Expr","name":"Expr","kind":"data","summary":"An expression (§7, §10): its form and source span.","text":"","module":"syntax","href":"module/syntax.html#syntax-Expr"},{"fqn":"syntax::ExprKind","name":"ExprKind","kind":"data","summary":"The expression forms (§10). `Marker` is a built-in generic constructor —\n`Ok`/`Err` (`Result`) or `Some`/`None` (`Option`); `From` names a target\ntype and its `source`, whose `FromSource` form is the §7.2 vs §7.4 split;\n`Postfix` is a `.name`/`.name(..)` access chain (ADR-007); `OwnCall` is a\nbare same-node call `Name(args)` (§5.1, ADR-041); `Unary`/`Binary` are the\n§7.5 operator forms. A `Marker` or `From` head is never a binary operand (§7.5).","text":"","module":"syntax","href":"module/syntax.html#syntax-ExprKind"},{"fqn":"syntax::ExprStmt","name":"ExprStmt","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-ExprStmt"},{"fqn":"syntax::FeatureDecl","name":"FeatureDecl","kind":"data","summary":"A `feature Name for Path { given* when+ then+ }` BDD scenario (§5.2). Steps\nare prose, not resolved against the model; the strict given→when→then order\nis enforced by the parser. A feature takes no macros and no `public`.","text":"","module":"syntax","href":"module/syntax.html#syntax-FeatureDecl"},{"fqn":"syntax::FeatureItem","name":"FeatureItem","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-FeatureItem"},{"fqn":"syntax::FeatureStep","name":"FeatureStep","kind":"data","summary":"One step line in a feature flow: a step keyword and its prose string (§5.2).","text":"","module":"syntax","href":"module/syntax.html#syntax-FeatureStep"},{"fqn":"syntax::Field","name":"Field","kind":"data","summary":"A record field `name: Type`.","text":"","module":"syntax","href":"module/syntax.html#syntax-Field"},{"fqn":"syntax::For","name":"For","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-For"},{"fqn":"syntax::From","name":"From","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-From"},{"fqn":"syntax::FromSource","name":"FromSource","kind":"data","summary":"The source of a `from` expression (§7.2, §7.4, ADR-035) — the parser\nbranches on the leading token, so the two forms are distinct: a `{`\nopens `Compose`, a set the target `data` record/variant is built from;\nanything else is `Convert`, carrying the target type onto one value.","text":"","module":"syntax","href":"module/syntax.html#syntax-FromSource"},{"fqn":"syntax::If","name":"If","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-If"},{"fqn":"syntax::InnerDoc","name":"InnerDoc","kind":"data","summary":"One `//!` inner-doc line documenting the module (§2.1).","text":"","module":"syntax","href":"module/syntax.html#syntax-InnerDoc"},{"fqn":"syntax::Item","name":"Item","kind":"data","summary":"A top-level item: a documented structural declaration, or a `feature` BDD\nscenario.","text":"","module":"syntax","href":"module/syntax.html#syntax-Item"},{"fqn":"syntax::Lexed","name":"Lexed","kind":"data","summary":"The full result of lexing: the conformance token stream plus interleaved\ntrivia for the formatter.","text":"","module":"syntax","href":"module/syntax.html#syntax-Lexed"},{"fqn":"syntax::Lexer","name":"Lexer","kind":"component","summary":"Hand-written lexer for LANG.md §2. One pass yields the conformance token\nstream (comments discarded, `///`→`Doc`+`Tag`, `//!`→`InnerDoc`) and\nfull-fidelity trivia for the formatter. Infallible: lexical anomalies surface\nas parser diagnostics, never a failed lex.","text":"","module":"syntax","href":"module/syntax.html#syntax-Lexer"},{"fqn":"syntax::LineComment","name":"LineComment","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-LineComment"},{"fqn":"syntax::LineIndex","name":"LineIndex","kind":"component","summary":"Precomputed newline offsets turning a byte offset into a 1-based (line, col)\npair in O(log n). Built once per source and reused for every lookup; column\ncounts bytes from the line start.","text":"","module":"syntax","href":"module/syntax.html#syntax-LineIndex"},{"fqn":"syntax::List","name":"List","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-List"},{"fqn":"syntax::Lit","name":"Lit","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Lit"},{"fqn":"syntax::Literal","name":"Literal","kind":"data","summary":"A literal value (ADR-013). `raw` carries the source text (string literals\nkeep their quotes).","text":"","module":"syntax","href":"module/syntax.html#syntax-Literal"},{"fqn":"syntax::LiteralArg","name":"LiteralArg","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-LiteralArg"},{"fqn":"syntax::Macro","name":"Macro","kind":"data","summary":"A `#[..]` macro (outer attribute) on a callable (§2.4): its name path and\nargument form.","text":"","module":"syntax","href":"module/syntax.html#syntax-Macro"},{"fqn":"syntax::MacroArg","name":"MacroArg","kind":"data","summary":"One argument inside a macro's `( .. )` list (§10 `MetaArg`).","text":"","module":"syntax","href":"module/syntax.html#syntax-MacroArg"},{"fqn":"syntax::MacroArgs","name":"MacroArgs","kind":"data","summary":"The three macro argument forms (§2.4): `#[manual]` word, `#[onevent(Path)]`/\n`#[http(\"..\")]` list, `#[schedule = \"..]` name=value.","text":"","module":"syntax","href":"module/syntax.html#syntax-MacroArgs"},{"fqn":"syntax::Marker","name":"Marker","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Marker"},{"fqn":"syntax::MarkerKind","name":"MarkerKind","kind":"data","summary":"The built-in generic constructor a `Marker` names (§6, ADR-019). The\nvariants mirror the four marker keywords (their names carry the `Kw` prefix\nbecause `Ok`/`Err`/`Some`/`None` are reserved words): `KwOk`/`KwErr` build a\n`Result`, `KwSome`/`KwNone` build an `Option`.","text":"","module":"syntax","href":"module/syntax.html#syntax-MarkerKind"},{"fqn":"syntax::Module","name":"Module","kind":"data","summary":"The typed syntax tree of one module (LANG.md §10): module-level inner docs,\nthen declarations and features in source order. Every node carries a `Span`;\ndeclarations and statements also carry leading trivia so the formatter can\nreproduce layout.","text":"","module":"syntax","href":"module/syntax.html#syntax-Module"},{"fqn":"syntax::NameValue","name":"NameValue","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-NameValue"},{"fqn":"syntax::NestedArg","name":"NestedArg","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-NestedArg"},{"fqn":"syntax::Node","name":"Node","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Node"},{"fqn":"syntax::NodeDecl","name":"NodeDecl","kind":"data","summary":"A `person` / `system` / `container` / `component` declaration. `parent` is\nthe `for <Parent>` path, present for container/component. `body` is the\ndisclosed member list, or absent for a black box (`;`).","text":"","module":"syntax","href":"module/syntax.html#syntax-NodeDecl"},{"fqn":"syntax::NodeKind","name":"NodeKind","kind":"data","summary":"The structural keyword class of a node.","text":"","module":"syntax","href":"module/syntax.html#syntax-NodeKind"},{"fqn":"syntax::NumberLit","name":"NumberLit","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-NumberLit"},{"fqn":"syntax::OwnCall","name":"OwnCall","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-OwnCall"},{"fqn":"syntax::Param","name":"Param","kind":"data","summary":"A callable parameter `name: Type`.","text":"","module":"syntax","href":"module/syntax.html#syntax-Param"},{"fqn":"syntax::Paren","name":"Paren","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Paren"},{"fqn":"syntax::Parsed","name":"Parsed","kind":"data","summary":"Parser output: the tree (always present, recovered on error) plus the\ndiagnostics collected while parsing. Parsing never fails outright.","text":"","module":"syntax","href":"module/syntax.html#syntax-Parsed"},{"fqn":"syntax::Parser","name":"Parser","kind":"component","summary":"Recursive-descent parser for the §10 grammar with error recovery: on\nunexpected input it records a `Diagnostic`, resynchronises to the next\nstatement/declaration boundary, and continues. Always yields a (possibly\npartial) `Module`; never panics.","text":"","module":"syntax","href":"module/syntax.html#syntax-Parser"},{"fqn":"syntax::Path","name":"Path","kind":"data","summary":"A `::`-separated path of identifiers (§2.2, §10 `Path`); never empty.","text":"","module":"syntax","href":"module/syntax.html#syntax-Path"},{"fqn":"syntax::PathArg","name":"PathArg","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-PathArg"},{"fqn":"syntax::PathRef","name":"PathRef","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-PathRef"},{"fqn":"syntax::Postfix","name":"Postfix","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Postfix"},{"fqn":"syntax::PostfixSeg","name":"PostfixSeg","kind":"data","summary":"One `.name` or `.name(args)` step in a postfix chain (ADR-007). `callArgs`\npresent marks a call; absent marks field access.","text":"","module":"syntax","href":"module/syntax.html#syntax-PostfixSeg"},{"fqn":"syntax::Record","name":"Record","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Record"},{"fqn":"syntax::Ref","name":"Ref","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Ref"},{"fqn":"syntax::Reference","name":"Reference","kind":"data","summary":"A reference primary (§10 `Ref`): an FQN. `self` was dropped (ADR-041); a\nsame-node call is the bare `OwnCall` primary, not a reference.","text":"","module":"syntax","href":"module/syntax.html#syntax-Reference"},{"fqn":"syntax::Return","name":"Return","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Return"},{"fqn":"syntax::Severity","name":"Severity","kind":"data","summary":"Diagnostic severity. `Error` invalidates the input; `Warning`/`Info` advise\nand never block compilation.","text":"","module":"syntax","href":"module/syntax.html#syntax-Severity"},{"fqn":"syntax::Span","name":"Span","kind":"data","summary":"A half-open byte range `[start, end)` into one module's source. Offsets are\nbytes, not characters; columns derived via `LineIndex` count bytes too,\nmatching the conformance token goldens.","text":"","module":"syntax","href":"module/syntax.html#syntax-Span"},{"fqn":"syntax::SpannedTrivia","name":"SpannedTrivia","kind":"data","summary":"A trivia element paired with the source span it occupies.","text":"","module":"syntax","href":"module/syntax.html#syntax-SpannedTrivia"},{"fqn":"syntax::StepKind","name":"StepKind","kind":"data","summary":"The step keyword class of a feature step (§5.2). `And`/`But` continue the\npreceding step's flow phase.","text":"","module":"syntax","href":"module/syntax.html#syntax-StepKind"},{"fqn":"syntax::Stmt","name":"Stmt","kind":"data","summary":"A statement valid inside a callable body (§7), with the leading trivia that\npreceded it.","text":"","module":"syntax","href":"module/syntax.html#syntax-Stmt"},{"fqn":"syntax::StmtKind","name":"StmtKind","kind":"data","summary":"The statement forms (§7).","text":"","module":"syntax","href":"module/syntax.html#syntax-StmtKind"},{"fqn":"syntax::StringLit","name":"StringLit","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-StringLit"},{"fqn":"syntax::Syntax","name":"Syntax","kind":"container","summary":"`crates/pseudoscript-syntax`. The foundation crate: source text to tokens\nand a typed AST, emitting the shared `Diagnostic`. WASM-safe and I/O-free.","text":"","module":"syntax","href":"module/syntax.html#syntax-Syntax"},{"fqn":"syntax::Tag","name":"Tag","kind":"data","summary":"A `\n` tag from a doc block, including the leading `#` (§2.4).","text":"","module":"syntax","href":"module/syntax.html#syntax-Tag"},{"fqn":"syntax::Token","name":"Token","kind":"data","summary":"A lexical token: its kind, source span, and rendered lexeme (LANG.md §2).","text":"For most tokens `text` is the raw source slice. For `Doc`/`InnerDoc` it is\nthe doc text with the marker and surrounding whitespace stripped; for `Tag`\nit includes the leading `#`.","module":"syntax","href":"module/syntax.html#syntax-Token"},{"fqn":"syntax::TokenKind","name":"TokenKind","kind":"data","summary":"Every lexical token class (LANG.md §2). The `name` rendering (e.g.\n`KW_SYSTEM`) is the conformance golden's `KIND`. Primitive type names and\n`Result` are NOT keywords — they lex as `Ident` and are classified in type\nposition by the model crate.","text":"","module":"syntax","href":"module/syntax.html#syntax-TokenKind"},{"fqn":"syntax::Trivia","name":"Trivia","kind":"data","summary":"Non-token source between tokens, preserved for the formatter. Doc comments,\ntags, macros, and modifiers are first-class tokens/AST data, not trivia —\nonly discarded comments and blank-line gaps live here.","text":"","module":"syntax","href":"module/syntax.html#syntax-Trivia"},{"fqn":"syntax::Type","name":"Type","kind":"data","summary":"A type expression: a named base with optional generic arguments and an\noptional trailing `[]` array suffix (§3.3, ADR-008 — no optionality marker).","text":"","module":"syntax","href":"module/syntax.html#syntax-Type"},{"fqn":"syntax::Unary","name":"Unary","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Unary"},{"fqn":"syntax::UnaryOp","name":"UnaryOp","kind":"data","summary":"A unary operator (§7.5): boolean `!` or numeric `-`.","text":"","module":"syntax","href":"module/syntax.html#syntax-UnaryOp"},{"fqn":"syntax::Union","name":"Union","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-Union"},{"fqn":"syntax::Variant","name":"Variant","kind":"data","summary":"One union variant: its name and an optional inline record body.","text":"","module":"syntax","href":"module/syntax.html#syntax-Variant"},{"fqn":"syntax::While","name":"While","kind":"data","summary":"","text":"","module":"syntax","href":"module/syntax.html#syntax-While"},{"fqn":"universe","name":"universe","kind":"module","summary":"","text":"","module":"universe","href":"module/universe.html"},{"fqn":"universe::Adapter","name":"Adapter","kind":"component","summary":"Adapts a resolved model into the software graph: keeps only the structural\nnodes, hooks each to its structural parent for the containment tree, and lifts\nevery call to the structural level — tallying directed traffic per\ncaller→callee pair so the edge carries direction.","text":"","module":"universe","href":"module/universe.html#universe-Adapter"},{"fqn":"universe::C4Level","name":"C4Level","kind":"data","summary":"The C4 abstraction level a node sits at. Only these four enter the graph;\ndata and callables do not — a relationship through them is lifted to the\nnearest enclosing structural node.","text":"","module":"universe","href":"module/universe.html#universe-C4Level"},{"fqn":"universe::EdgeOut","name":"EdgeOut","kind":"data","summary":"One relationship in the flat snapshot, with its traffic (call count).","text":"","module":"universe","href":"module/universe.html#universe-EdgeOut"},{"fqn":"universe::Flatten","name":"Flatten","kind":"component","summary":"Flattens the software graph into the renderer-facing snapshot: each node's id,\nlevel string, and parent id; each relationship's endpoints and traffic. The\nboundary the web IDE reads — petgraph indices never cross it.","text":"","module":"universe","href":"module/universe.html#universe-Flatten"},{"fqn":"universe::FlowDef","name":"FlowDef","kind":"data","summary":"One entry-point flow: the entry callable's FQN and simple name, the flow's\npalette colour, and its ordered legs. The renderer draws one filament chain\nper flow and streams its beads in the flow's colour.","text":"","module":"universe","href":"module/universe.html#universe-FlowDef"},{"fqn":"universe::FlowHop","name":"FlowHop","kind":"data","summary":"One call leg of a flow: the caller and callee as structural node ids (the\nsame ids the snapshot places), plus the message label shown on the leg.","text":"","module":"universe","href":"module/universe.html#universe-FlowHop"},{"fqn":"universe::FlowTracer","name":"FlowTracer","kind":"component","summary":"Traces every entry-point flow: a triggered callable (or a person-owned\naction) starts a flow; its sequence projection is walked call-by-call and\neach leg's endpoints lift to the nearest placed structural node — the same\nlift the Adapter applies to relationships, so flows and edges agree. Colours\nkey from the entry's FQN by a stable hash into a fixed palette — the same\nkeying the web IDE paints with — so a flow keeps its hue everywhere it\nappears and an unrelated model edit never recolours it.","text":"","module":"universe","href":"module/universe.html#universe-FlowTracer"},{"fqn":"universe::GraphNode","name":"GraphNode","kind":"data","summary":"A structural node in the software graph: its stable model FQN, its C4 level,\nand its place in the containment tree (the enclosing node, empty for a\ntop-level system, and the ids it contains). No position — the renderer\nplaces it.","text":"","module":"universe","href":"module/universe.html#universe-GraphNode"},{"fqn":"universe::NodeOut","name":"NodeOut","kind":"data","summary":"One node in the flat snapshot: its id, C4 level as a lowercase string, and the\nid of its containment parent (empty for a top-level system).","text":"","module":"universe","href":"module/universe.html#universe-NodeOut"},{"fqn":"universe::Relationship","name":"Relationship","kind":"data","summary":"A directed relationship between two structural nodes, weighted by `traffic` —\nthe number of underlying calls lifted onto the pair. Self-relationships are\ndropped; the count drives the renderer's flow animation.","text":"","module":"universe","href":"module/universe.html#universe-Relationship"},{"fqn":"universe::Snapshot","name":"Snapshot","kind":"data","summary":"The flat, serialisable contract the web IDE's `ForceGraph` consumes: nodes\nand directed weighted edges, with no engine internals (petgraph indices)\nleaking across the boundary. Positions are not here.","text":"","module":"universe","href":"module/universe.html#universe-Snapshot"},{"fqn":"universe::SoftwareGraph","name":"SoftwareGraph","kind":"data","summary":"The software graph: structural nodes with the containment tree, directed\nrelationship edges weighted by traffic, and the top-level systems (the\ncontainment roots, in model-declaration order). The crate's in-memory form,\nbefore flattening to a renderer-facing `Snapshot`.","text":"","module":"universe","href":"module/universe.html#universe-SoftwareGraph"},{"fqn":"universe::Universe","name":"Universe","kind":"container","summary":"`crates/pseudoscript-universe`. Maps the resolved C4 model into the software\ngraph the 3D view renders, then flattens it to a determinstic snapshot.","text":"","module":"universe","href":"module/universe.html#universe-Universe"},{"fqn":"universe.html","name":"3D Universe","kind":"page","summary":"The model in 3D — structure and flows","text":"","module":"","href":"universe.html"}];